{
  "name": "CoopConnect BC",
  "description": "A comprehensive management platform for British Columbia housing co-operatives, featuring tenant tracking, maintenance workflows, document management, and AI-powered policy assistance.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum RequestStatus {
  PENDING = 'Pending',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  CANCELLED = 'Cancelled'
}

export interface Unit {
  id: string;
  number: string;
  type: '1BR' | '2BR' | '3BR' | '4BR';
  floor: number;
  currentTenantId?: string;
  status: 'Occupied' | 'Vacant' | 'Maintenance';
}

export interface Tenant {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  unitId?: string;
  startDate: string;
  endDate?: string;
  status: 'Current' | 'Past' | 'Waitlist';
}

export interface MaintenanceRequest {
  id: string;
  unitId: string;
  tenantId: string;
  category: 'Plumbing' | 'Electrical' | 'Structural' | 'Appliance' | 'Other';
  description: string;
  urgency: 'Low' | 'Medium' | 'High' | 'Emergency';
  status: RequestStatus;
  createdAt: string;
  updatedAt: string;
  notes?: string;
}

export interface Document {
  id: string;
  title: string;
  category: 'Minutes' | 'Policy' | 'Financial' | 'Committee' | 'Bylaws';
  date: string;
  author: string;
}

export interface UserRole {
  isAdmin: boolean;
  coopName: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  /**
   * Triage a maintenance request based on description
   */
  async triageMaintenanceRequest(description: string) {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Evaluate the following maintenance request for a BC housing co-op and return a suggested urgency level (Low, Medium, High, Emergency) and a category (Plumbing, Electrical, Structural, Appliance, Other). 
      Request: "${description}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            urgency: { type: Type.STRING },
            category: { type: Type.STRING },
            reasoning: { type: Type.STRING }
          },
          required: ["urgency", "category"]
        }
      }
    });

    try {
      return JSON.parse(response.text || '{}');
    } catch (e) {
      return { urgency: 'Medium', category: 'Other' };
    }
  },

  /**
   * Answer questions based on Co-op Policies
   */
  async askPolicyQuestion(question: string, context: string) {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an AI assistant for a BC Housing Co-operative. Answer the following member question based strictly on the provided policy snippets. If the answer isn't in the context, say you don't know and advise them to contact the board.

      Context: ${context}
      Question: ${question}`,
      config: {
        temperature: 0.2
      }
    });
    return response.text;
  }
};

import React from 'react';
import { Link, useLocation } from 'react-router-dom';

interface LayoutProps {
  children: React.ReactNode;
  isAdmin: boolean;
  onToggleAdmin: () => void;
  coopName: string;
}

const Layout: React.FC<LayoutProps> = ({ children, isAdmin, onToggleAdmin, coopName }) => {
  const location = useLocation();

  const navItems = [
    { label: 'Dashboard', path: '/', icon: 'fa-chart-line' },
    { label: 'Maintenance', path: '/maintenance', icon: 'fa-tools' },
    { label: 'Documents', path: '/documents', icon: 'fa-file-lines' },
    { label: 'Directory', path: '/directory', icon: 'fa-address-book' },
  ];

  if (isAdmin) {
    navItems.push(
      { label: 'Units', path: '/admin/units', icon: 'fa-house-chimney' },
      { label: 'Tenants', path: '/admin/tenants', icon: 'fa-users' },
      { label: 'Reports', path: '/admin/reports', icon: 'fa-chart-pie' }
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col shrink-0">
        <div className="p-6">
          <h1 className="text-xl font-bold flex items-center gap-2">
            <i className="fa-solid fa-house-signal text-emerald-400"></i>
            <span>{coopName}</span>
          </h1>
          <p className="text-xs text-slate-400 mt-1 uppercase tracking-widest font-semibold">Co-op Management</p>
        </div>

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors ${
                location.pathname === item.path
                  ? 'bg-emerald-600 text-white'
                  : 'text-slate-300 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <i className={`fa-solid ${item.icon} w-5`}></i>
              <span className="text-sm font-medium">{item.label}</span>
            </Link>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <button
            onClick={onToggleAdmin}
            className={`w-full flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
              isAdmin 
                ? 'bg-amber-500/10 text-amber-500 border border-amber-500/20' 
                : 'bg-slate-800 text-slate-300 hover:bg-slate-700'
            }`}
          >
            <i className={`fa-solid ${isAdmin ? 'fa-user-shield' : 'fa-user'}`}></i>
            {isAdmin ? 'Admin Mode' : 'Switch to Admin'}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 shadow-sm">
          <div className="flex items-center gap-4">
             <h2 className="text-lg font-semibold text-slate-700">
               {navItems.find(n => n.path === location.pathname)?.label || 'Page'}
             </h2>
          </div>
          <div className="flex items-center gap-4">
            <button className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
              <i className="fa-solid fa-bell"></i>
            </button>
            <div className="w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center text-white font-bold text-sm">
              BC
            </div>
          </div>
        </header>
        <section className="flex-1 overflow-y-auto p-8">
          {children}
        </section>
      </main>
    </div>
  );
};

export default Layout;

import React from 'react';

interface StatCardProps {
  label: string;
  value: string | number;
  icon: string;
  trend?: string;
  color: string;
}

const StatCard: React.FC<StatCardProps> = ({ label, value, icon, trend, color }) => {
  return (
    <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
      <div className="flex items-center justify-between mb-4">
        <div className={`w-12 h-12 rounded-lg ${color} flex items-center justify-center text-white text-xl shadow-lg`}>
          <i className={`fa-solid ${icon}`}></i>
        </div>
        {trend && (
          <span className={`text-xs font-bold px-2 py-1 rounded-full ${trend.startsWith('+') ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
            {trend}
          </span>
        )}
      </div>
      <div>
        <p className="text-slate-500 text-sm font-medium">{label}</p>
        <h3 className="text-2xl font-bold text-slate-900 mt-1">{value}</h3>
      </div>
