  );
};

export default StatCard;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import StatCard from '../components/StatCard';
import { MOCK_UNITS, MOCK_REQUESTS } from '../constants';
import { RequestStatus } from '../types';

const Dashboard: React.FC = () => {
  const occupiedCount = MOCK_UNITS.filter(u => u.status === 'Occupied').length;
  const pendingRequests = MOCK_REQUESTS.filter(r => r.status === RequestStatus.PENDING).length;

  const chartData = [
    { name: '1BR', count: MOCK_UNITS.filter(u => u.type === '1BR').length },
    { name: '2BR', count: MOCK_UNITS.filter(u => u.type === '2BR').length },
    { name: '3BR', count: MOCK_UNITS.filter(u => u.type === '3BR').length },
    { name: '4BR', count: MOCK_UNITS.filter(u => u.type === '4BR').length },
  ];

  const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#8b5cf6'];

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Total Units" value={MOCK_UNITS.length} icon="fa-building" color="bg-emerald-500" />
        <StatCard label="Occupancy Rate" value={`${(occupiedCount / MOCK_UNITS.length * 100).toFixed(1)}%`} icon="fa-users" color="bg-blue-500" trend="+2.5%" />
        <StatCard label="Open Requests" value={pendingRequests} icon="fa-wrench" color="bg-amber-500" />
        <StatCard label="Policy Queries" value="12" icon="fa-comment-dots" color="bg-purple-500" trend="+12" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Unit Distribution</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip 
                   contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Recent Maintenance</h3>
          <div className="space-y-4">
            {MOCK_REQUESTS.slice(0, 5).map(req => (
              <div key={req.id} className="flex gap-4 pb-4 border-b border-slate-100 last:border-0">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 ${
                  req.urgency === 'High' || req.urgency === 'Emergency' ? 'bg-rose-100 text-rose-600' : 'bg-slate-100 text-slate-600'
                }`}>
                  <i className="fa-solid fa-screwdriver-wrench text-sm"></i>
                </div>
                <div>
                  <p className="text-sm font-semibold text-slate-800 line-clamp-1">{req.description}</p>
                  <p className="text-xs text-slate-500 mt-0.5">Unit {MOCK_UNITS.find(u => u.id === req.unitId)?.number} • {req.status}</p>
                </div>
              </div>
            ))}
          </div>
          <button className="w-full mt-4 text-emerald-600 font-semibold text-sm hover:underline">View all requests</button>
        </div>
      </div>

      {/* PIPA Compliance Banner */}
      <div className="bg-emerald-50 border border-emerald-200 p-4 rounded-xl flex items-start gap-4">
        <div className="text-emerald-600 mt-1">
          <i className="fa-solid fa-shield-halved text-xl"></i>
        </div>
        <div>
          <h4 className="text-emerald-800 font-bold">Privacy Compliant (PIPA)</h4>
          <p className="text-emerald-700 text-sm leading-relaxed">
            CoopConnect BC is designed to adhere to British Columbia's Personal Information Protection Act. All sensitive tenant data is encrypted and access is restricted by role.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { MaintenanceRequest, RequestStatus } from '../types';
import { MOCK_REQUESTS, MOCK_UNITS } from '../constants';
import { geminiService } from '../services/geminiService';

const Maintenance: React.FC = () => {
  const [requests, setRequests] = useState<MaintenanceRequest[]>(MOCK_REQUESTS);
  const [showForm, setShowForm] = useState(false);
  const [loading, setLoading] = useState(false);
  const [description, setDescription] = useState('');
  const [unitId, setUnitId] = useState('');
  const [category, setCategory] = useState('Other');
  const [urgency, setUrgency] = useState('Low');

  const handleTriage = async () => {
    if (!description || description.length < 10) return;
    setLoading(true);
    try {
      const result = await geminiService.triageMaintenanceRequest(description);
      if (result.category) setCategory(result.category);
      if (result.urgency) setUrgency(result.urgency);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newRequest: MaintenanceRequest = {
      id: `r${Date.now()}`,
      unitId,
      tenantId: 't1', // Hardcoded for demo
      category: category as any,
      description,
      urgency: urgency as any,
      status: RequestStatus.PENDING,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };
    setRequests([newRequest, ...requests]);
    setShowForm(false);
    setDescription('');
    setUnitId('');
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Maintenance Portal</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 transition-colors"
        >
          <i className="fa-solid fa-plus"></i>
          New Request
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-lg animate-in fade-in slide-in-from-top-4">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Submit Repair Request</h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Detailed Description</label>
              <textarea
                className="w-full border border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none"
                rows={3}
                placeholder="What needs fixing? E.g. 'The faucet in the upstairs bathroom has been dripping since yesterday...'"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                onBlur={handleTriage}
                required
              />
              {loading && <p className="text-xs text-emerald-600 mt-1 animate-pulse"><i className="fa-solid fa-wand-sparkles mr-1"></i> AI is triaging your request...</p>}
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Unit Number</label>
              <select 
                className="w-full border border-slate-300 rounded-lg p-2.5 outline-none"
                value={unitId}
                onChange={(e) => setUnitId(e.target.value)}
                required
              >
                <option value="">Select Unit</option>
                {MOCK_UNITS.map(u => <option key={u.id} value={u.id}>Unit {u.number}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
              <select 
                className="w-full border border-slate-300 rounded-lg p-2.5 outline-none"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
              >
                <option>Plumbing</option>
                <option>Electrical</option>
                <option>Appliance</option>
                <option>Structural</option>
                <option>Other</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Urgency</label>
              <select 
                className="w-full border border-slate-300 rounded-lg p-2.5 outline-none"
                value={urgency}
                onChange={(e) => setUrgency(e.target.value)}
              >
                <option>Low</option>
                <option>Medium</option>
                <option>High</option>
                <option>Emergency</option>
              </select>
            </div>

            <div className="md:col-span-2 flex justify-end gap-3 mt-4">
              <button 
                type="button" 
                onClick={() => setShowForm(false)}
                className="px-4 py-2 text-slate-600 font-medium hover:bg-slate-100 rounded-lg"
              >
                Cancel
              </button>
              <button 
                type="submit"
                className="px-6 py-2 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-700"
              >
                Submit Request
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 text-sm font-bold text-slate-600">ID</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-600">Unit</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-600">Category</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-600">Description</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-600">Urgency</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-600">Status</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-600">Date</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {requests.map(req => (
              <tr key={req.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-sm font-mono text-slate-500 uppercase">{req.id}</td>
                <td className="px-6 py-4 text-sm font-semibold text-slate-800">
                  {MOCK_UNITS.find(u => u.id === req.unitId)?.number}
                </td>
                <td className="px-6 py-4 text-sm text-slate-600">{req.category}</td>
                <td className="px-6 py-4 text-sm text-slate-600 max-w-xs truncate">{req.description}</td>
                <td className="px-6 py-4">
                  <span className={`text-xs font-bold px-2 py-1 rounded-full ${
                    req.urgency === 'Emergency' ? 'bg-rose-100 text-rose-600' :
                    req.urgency === 'High' ? 'bg-amber-100 text-amber-600' :
                    'bg-slate-100 text-slate-600'
                  }`}>
                    {req.urgency}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2">
                    <span className={`w-2 h-2 rounded-full ${
                      req.status === RequestStatus.COMPLETED ? 'bg-emerald-500' :
                      req.status === RequestStatus.IN_PROGRESS ? 'bg-blue-500' :
                      'bg-slate-300'
                    }`}></span>
                    <span className="text-sm font-medium text-slate-700">{req.status}</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-sm text-slate-500">
                  {new Date(req.createdAt).toLocaleDateString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Maintenance;

import React, { useState } from 'react';
import { MOCK_DOCS } from '../constants';
import { geminiService } from '../services/geminiService';

const Documents: React.FC = () => {
  const [filter, setFilter] = useState('All');
  const [question, setQuestion] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [loading, setLoading] = useState(false);

  const categories = ['All', 'Minutes', 'Policy', 'Financial', 'Bylaws'];
  const filteredDocs = filter === 'All' ? MOCK_DOCS : MOCK_DOCS.filter(d => d.category === filter);

  const handleAskAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!question) return;
    setLoading(true);
    setAiResponse('');

    // In a real app, we would search document content. For demo, we use policy names.
    const context = MOCK_DOCS.filter(d => d.category === 'Policy').map(d => d.title).join(', ');

    try {
      const answer = await geminiService.askPolicyQuestion(question, context);
      setAiResponse(answer || 'Sorry, I could not find an answer.');
    } catch (err) {
      setAiResponse('Error communicating with AI Assistant.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8">
      {/* AI Policy Assistant */}
      <div className="bg-gradient-to-br from-slate-900 to-slate-800 rounded-2xl p-6 text-white shadow-xl">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-emerald-500 rounded-lg flex items-center justify-center">
            <i className="fa-solid fa-robot"></i>
          </div>
          <div>
            <h3 className="text-lg font-bold">Policy Assistant</h3>
            <p className="text-xs text-slate-400">Ask about co-op rules, bylaws, or policies.</p>
          </div>
        </div>
        <form onSubmit={handleAskAI} className="relative">
          <input
            type="text"
            className="w-full bg-slate-700/50 border border-slate-600 rounded-xl px-5 py-3 pr-24 outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm"
            placeholder="Can I have a pet in a 2BR unit?"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
          />
          <button 
            type="submit"
            disabled={loading}
            className="absolute right-2 top-2 bottom-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 rounded-lg text-sm font-bold transition-colors flex items-center gap-2"
          >
            {loading ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-paper-plane"></i>}
            Ask
          </button>
        </form>
        {aiResponse && (
          <div className="mt-4 p-4 bg-slate-800/50 border border-slate-700 rounded-xl text-sm leading-relaxed animate-in fade-in zoom-in-95">
            <p className="text-emerald-400 font-bold mb-1 flex items-center gap-2">
               <i className="fa-solid fa-wand-sparkles text-xs"></i>
               Assistant Answer:
            </p>
            {aiResponse}
          </div>
        )}
      </div>

      <div className="flex flex-col md:flex-row gap-6">
        {/* Categories */}
        <div className="w-full md:w-64 space-y-1">
          <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3 px-2">Categories</h4>
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`w-full text-left px-3 py-2 rounded-lg text-sm font-medium transition-all ${
                filter === cat ? 'bg-white shadow-sm text-emerald-600 border border-slate-200' : 'text-slate-600 hover:bg-slate-200'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Document List */}
        <div className="flex-1 space-y-4">
           <div className="flex justify-between items-center mb-2">
             <h3 className="font-bold text-slate-800">{filter} Documents</h3>
             <span className="text-xs text-slate-500 font-medium">{filteredDocs.length} files</span>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             {filteredDocs.map(doc => (
