import React, { useState } from 'react';
import { MOCK_DOCS } from '../constants';
import { geminiService } from '../services/geminiService';

const Documents: React.FC<{ isAdmin: boolean }> = ({ isAdmin }) => {
  const [filter, setFilter] = useState('All');
  const [question, setQuestion] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [showUpload, setShowUpload] = useState(false);

  const categories = ['All', 'Minutes', 'Policy', 'Financial', 'Bylaws'];
  const filteredDocs = filter === 'All' ? MOCK_DOCS : MOCK_DOCS.filter(d => d.category === filter);

  const handleAskAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!question) return;
    setLoading(true);
    setAiResponse('');

    const context = MOCK_DOCS.filter(d => d.category === 'Policy').map(d => d.title).join(', ');

    try {
      const answer = await geminiService.askPolicyQuestion(question, context);
      setAiResponse(answer || 'Sorry, I could not find an answer.');
    } catch (err) {
      setAiResponse('Error communicating with AI Assistant.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8">
      {/* AI Policy Assistant */}
      <div className="bg-gradient-to-br from-slate-900 to-slate-800 rounded-2xl p-6 text-white shadow-xl">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-emerald-500 rounded-lg flex items-center justify-center">
            <i className="fa-solid fa-robot"></i>
          </div>
          <div>
            <h3 className="text-lg font-bold">Policy Assistant</h3>
            <p className="text-xs text-slate-400">Ask about co-op rules, bylaws, or policies.</p>
          </div>
        </div>
        <form onSubmit={handleAskAI} className="relative">
          <input
            type="text"
            className="w-full bg-slate-700/50 border border-slate-600 rounded-xl px-5 py-3 pr-24 outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm"
            placeholder="Can I have a pet in a 2BR unit?"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
          />
          <button 
            type="submit"
            disabled={loading}
            className="absolute right-2 top-2 bottom-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 rounded-lg text-sm font-bold transition-colors flex items-center gap-2"
          >
            {loading ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-paper-plane"></i>}
            Ask
          </button>
        </form>
        {aiResponse && (
          <div className="mt-4 p-4 bg-slate-800/50 border border-slate-700 rounded-xl text-sm leading-relaxed animate-in fade-in zoom-in-95">
            <p className="text-emerald-400 font-bold mb-1 flex items-center gap-2">
