        <Link to="/admin/units" className="block hover:scale-[1.02] transition-transform">
          <StatCard label="Total Units" value={MOCK_UNITS.length} icon="fa-building" color="bg-emerald-500" />
        </Link>
        <div className="block cursor-default">
          <StatCard label="Occupancy Rate" value={`${(occupiedCount / MOCK_UNITS.length * 100).toFixed(1)}%`} icon="fa-users" color="bg-blue-500" trend="+2.5%" />
        </div>
        <Link to="/maintenance" className="block hover:scale-[1.02] transition-transform">
          <StatCard label="Open Requests" value={pendingRequests} icon="fa-wrench" color="bg-amber-500" />
        </Link>
        <Link to="/documents" className="block hover:scale-[1.02] transition-transform">
          <StatCard label="Policy Queries" value="12" icon="fa-comment-dots" color="bg-purple-500" trend="+12" />
        </Link>
      </div>

      {/* Visual Unit Status Grid (Simplified Floor Plan) */}
      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold text-slate-800">Site Map Status</h3>
          <div className="flex gap-4 text-[10px] font-bold uppercase tracking-wider">
