            <span className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-full bg-slate-300"></div> Vacant</span>
            <span className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-full bg-amber-500"></div> Maintenance</span>
          </div>
        </div>
        <div className="grid grid-cols-5 md:grid-cols-10 gap-3">
          {MOCK_UNITS.map(unit => (
            <button
              key={unit.id}
              onClick={() => navigate(`/admin/units/${unit.id}`)}
              className={`aspect-square rounded-xl border-2 flex flex-col items-center justify-center transition-all hover:scale-110 active:scale-95 ${
                unit.status === 'Occupied' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' :
                unit.status === 'Vacant' ? 'bg-slate-50 border-slate-300 text-slate-500' :
                'bg-amber-50 border-amber-500 text-amber-700'
              }`}
            >
              <span className="text-xs font-black">{unit.number}</span>
              <i className="fa-solid fa-house text-[10px] mt-0.5 opacity-40"></i>
            </button>
          ))}
          {/* Fillers for visual effect */}
          {[...Array(5)].map((_, i) => (
             <div key={i} className="aspect-square rounded-xl border-2 border-slate-100 bg-slate-50/30 flex items-center justify-center">
