export default App;

export enum RequestStatus {
  PENDING = 'Pending',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  CANCELLED = 'Cancelled'
}

export interface Unit {
  id: string;
  number: string;
  type: '1BR' | '2BR' | '3BR' | '4BR';
  floor: number;
  currentTenantId?: string;
  status: 'Occupied' | 'Vacant' | 'Maintenance';
  lastInspectionDate?: string;
  ownerEmail?: string; // Added owner/primary member email
}

export interface Tenant {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  unitId?: string;
  startDate: string;
  endDate?: string;
  status: 'Current' | 'Past' | 'Waitlist';
  balance?: number;
}

export interface MaintenanceRequest {
  id: string;
  unitId: string;
  tenantId: string;
  category: 'Plumbing' | 'Electrical' | 'Structural' | 'Appliance' | 'Other';
  description: string;
  urgency: 'Low' | 'Medium' | 'High' | 'Emergency';
  status: RequestStatus;
  createdAt: string;
  updatedAt: string;
  notes?: string;
  attachments?: string[]; // Added for document links
}

export interface Document {
  id: string;
  title: string;
  category: 'Minutes' | 'Policy' | 'Financial' | 'Committee' | 'Bylaws' | 'Unit' | 'Repair';
  date: string;
  author: string;
  isPrivate?: boolean;
  relatedId?: string; // Link to Unit or Request
}

export interface Transaction {
  id: string;
  tenantId: string;
  amount: number;
  type: 'Housing Charge' | 'Maintenance Fee' | 'Parking' | 'Other';
  status: 'Paid' | 'Pending' | 'Overdue';
  date: string;
  description: string;
}

export interface Announcement {
  id: string;
  title: string;
  content: string;
  author: string;
  date: string;
  priority: 'Normal' | 'Urgent';
}

export interface Message {
  id: string;
  fromId: string;
  toId: string;
  toCommitteeId?: string; // Optional for committee routing
  body: string;
  timestamp: string;
}

export interface CoopEvent {
  id: string;
  title: string;
  date: string;
  time: string;
  location: string;
  category: 'Meeting' | 'Social' | 'Maintenance' | 'Board';
  description: string;
}

export interface Committee {
  id: string;
  name: string;
  description: string;
  chair: string;
  members: string[];
  icon: string;
}

export interface ScheduledMaintenance {
  id: string;
  unitId: string;
  task: string;
  dueDate: string;
  frequency: 'Monthly' | 'Quarterly' | 'Annual';
  assignedTo: string;
  isCompleted?: boolean;
}

