    const q = query(collection(db, "maintenanceRequests"), orderBy("createdAt", "desc"));
    return onSnapshot(q, (snapshot) => {
      const requests = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MaintenanceRequest));
      callback(requests);
    });
