import { 
  collection, 
  getDocs, 
  addDoc, 
  updateDoc, 
  doc, 
  query, 
  where, 
  orderBy, 
  onSnapshot,
  Timestamp,
  getDoc,
  arrayUnion
} from "firebase/firestore";
import { db } from "../firebase";
import { Unit, MaintenanceRequest, Announcement, CoopEvent, Tenant, RequestStatus } from "../types";

export const dbService = {
  // Units
  async getUnits(): Promise<Unit[]> {
    const querySnapshot = await getDocs(collection(db, "units"));
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Unit));
  },

  async getUnitById(id: string): Promise<Unit | null> {
    const docSnap = await getDoc(doc(db, "units", id));
    return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } as Unit : null;
  },

  // Maintenance Requests
  async createMaintenanceRequest(request: Omit<MaintenanceRequest, 'id'>) {
    return await addDoc(collection(db, "maintenanceRequests"), {
      ...request,
      createdAt: Timestamp.now().toDate().toISOString(),
      updatedAt: Timestamp.now().toDate().toISOString(),
    });
  },

  async updateMaintenanceRequest(id: string, updates: Partial<MaintenanceRequest>) {
    const requestDoc = doc(db, "maintenanceRequests", id);
    return await updateDoc(requestDoc, {
      ...updates,
      updatedAt: Timestamp.now().toDate().toISOString()
    });
  },

  async addAttachmentToRequest(id: string, fileUrl: string) {
    const requestDoc = doc(db, "maintenanceRequests", id);
    return await updateDoc(requestDoc, {
      attachments: arrayUnion(fileUrl),
      updatedAt: Timestamp.now().toDate().toISOString()
    });
  },

  subscribeToRequests(callback: (requests: MaintenanceRequest[]) => void) {
    const q = query(collection(db, "maintenanceRequests"), orderBy("createdAt", "desc"));
    return onSnapshot(q, (snapshot) => {
      const requests = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MaintenanceRequest));
      callback(requests);
    });
  },

  // Announcements
  subscribeToAnnouncements(callback: (announcements: Announcement[]) => void) {
    const q = query(collection(db, "announcements"), orderBy("date", "desc"));
    return onSnapshot(q, (snapshot) => {
      callback(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Announcement)));
    });
  },

  // Events
  subscribeToEvents(callback: (events: CoopEvent[]) => void) {
    const q = query(collection(db, "events"), orderBy("date", "asc"));
    return onSnapshot(q, (snapshot) => {
      callback(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as CoopEvent)));
    });
  },

  // Tenants
  async getTenantsForUnit(unitId: string): Promise<Tenant[]> {
    const q = query(collection(db, "tenants"), where("unitId", "==", unitId));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Tenant));
  }
};

