import React, { useState } from 'react';
import { MaintenanceRequest, RequestStatus } from '../types';
import { MOCK_REQUESTS, MOCK_UNITS } from '../constants';
import { geminiService } from '../services/geminiService';

interface MaintenanceProps {
  isAdmin?: boolean;
}

const Maintenance: React.FC<MaintenanceProps> = ({ isAdmin = false }) => {
  const [requests, setRequests] = useState<MaintenanceRequest[]>(MOCK_REQUESTS);
  const [showForm, setShowForm] = useState(false);
  const [loading, setLoading] = useState(false);
  const [description, setDescription] = useState('');
  const [unitId, setUnitId] = useState('');
  const [category, setCategory] = useState('Other');
  const [urgency, setUrgency] = useState('Low');

  const handleTriage = async () => {
    if (!description || description.length < 10) return;
    setLoading(true);
    try {
      const result = await geminiService.triageMaintenanceRequest(description);
      if (result.category) setCategory(result.category);
      if (result.urgency) setUrgency(result.urgency);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newRequest: MaintenanceRequest = {
      id: `r${Date.now()}`,
      unitId,
      tenantId: 't1', 
      category: category as any,
      description,
      urgency: urgency as any,
      status: RequestStatus.PENDING,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      attachments: []
    };
    setRequests([newRequest, ...requests]);
    setShowForm(false);
    setDescription('');
    setUnitId('');
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800">Maintenance Portal</h2>
          <p className="text-slate-500 text-sm">Track and report community repairs.</p>
