                onChange={(e) => setDescription(e.target.value)}
                onBlur={handleTriage}
                required
              />
              {loading && <p className="text-xs text-emerald-600 mt-2 font-bold animate-pulse"><i className="fa-solid fa-wand-sparkles mr-2"></i> Analyzing with AI...</p>}
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Unit</label>
              <select 
                className="w-full border border-slate-200 rounded-xl p-3 text-sm outline-none bg-white appearance-none"
                value={unitId}
                onChange={(e) => setUnitId(e.target.value)}
                required
              >
                <option value="">Select Unit</option>
                {MOCK_UNITS.map(u => <option key={u.id} value={u.id}>Unit {u.number}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Category</label>
                <select 
                  className="w-full border border-slate-200 rounded-xl p-3 text-sm outline-none bg-white"
                  value={category}
                  onChange={(e) => setCategory(e.target.value)}
                >
                  <option>Plumbing</option>
                  <option>Electrical</option>
                  <option>Appliance</option>
                  <option>Structural</option>
                  <option>Other</option>
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Urgency</label>
                <select 
                  className="w-full border border-slate-200 rounded-xl p-3 text-sm outline-none bg-white"
                  value={urgency}
                  onChange={(e) => setUrgency(e.target.value)}
                >
                  <option>Low</option>
                  <option>Medium</option>
                  <option>High</option>
                  <option>Emergency</option>
