                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="text-sm font-bold text-slate-800">Unit {MOCK_UNITS.find(u => u.id === req.unitId)?.number}</span>
                    <span className="text-xs text-slate-500 truncate max-w-xs">{req.description}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="text-[10px] font-black bg-slate-100 text-slate-600 px-2 py-1 rounded-lg uppercase tracking-tight border border-slate-200">{req.category}</span>
                </td>
                <td className="px-6 py-4">
                  <span className={`text-[10px] font-black px-2 py-1 rounded-lg uppercase ${
                    req.urgency === 'Emergency' ? 'bg-rose-100 text-rose-700' :
