import React, { useState } from 'react';
import { MOCK_DOCS } from '../constants';
import { geminiService } from '../services/geminiService';

const Documents: React.FC<{ isAdmin: boolean }> = ({ isAdmin }) => {
  const [filter, setFilter] = useState('All');
  const [question, setQuestion] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [showUpload, setShowUpload] = useState(false);

  const categories = ['All', 'Minutes', 'Policy', 'Financial', 'Bylaws'];
  const filteredDocs = filter === 'All' ? MOCK_DOCS : MOCK_DOCS.filter(d => d.category === filter);

  const handleAskAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!question) return;
    setLoading(true);
    setAiResponse('');

    const context = MOCK_DOCS.filter(d => d.category === 'Policy').map(d => d.title).join(', ');

    try {
      const answer = await geminiService.askPolicyQuestion(question, context);
      setAiResponse(answer || 'Sorry, I could not find an answer.');
    } catch (err) {
      setAiResponse('Error communicating with AI Assistant.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6 lg:space-y-8 max-w-7xl mx-auto">
      {/* AI Policy Assistant */}
      <div className="bg-slate-900 rounded-2xl lg:rounded-3xl p-5 lg:p-8 text-white shadow-xl">
        <div className="flex items-center gap-3 mb-6">
          <div className="w-10 h-10 lg:w-12 lg:h-12 bg-emerald-500 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-500/20">
            <i className="fa-solid fa-robot text-lg lg:text-xl"></i>
          </div>
          <div>
            <h3 className="text-base lg:text-lg font-black">AI Policy Assistant</h3>
            <p className="text-xs text-slate-400 font-medium">Instant answers to co-op regulations.</p>
          </div>
        </div>
        <form onSubmit={handleAskAI} className="relative">
          <input
            type="text"
            className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3.5 lg:pr-24 outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm font-medium"
            placeholder="What is the pet limit?"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
          />
          <button 
            type="submit"
            disabled={loading}
            className="hidden lg:flex absolute right-2 top-2 bottom-2 bg-emerald-600 hover:bg-emerald-700 text-white px-5 rounded-lg text-xs font-black uppercase transition-colors items-center gap-2"
          >
            {loading ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-wand-sparkles"></i>}
