            {loading ? 'Thinking...' : 'Get Answer'}
          </button>
        </form>
        {aiResponse && (
          <div className="mt-6 p-4 bg-emerald-500/5 border border-emerald-500/20 rounded-xl text-sm leading-relaxed animate-in fade-in slide-in-from-top-2">
            <div className="flex items-center gap-2 mb-2">
              <div className="w-1 h-4 bg-emerald-500 rounded-full"></div>
              <span className="text-xs font-black text-emerald-400 uppercase tracking-widest">Response</span>
            </div>
            <p className="text-slate-300 font-medium">{aiResponse}</p>
          </div>
        )}
      </div>

      {/* Library Section */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <h3 className="text-xl font-black text-slate-800">Resource Library</h3>
