import React, { useState, useRef, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { MOCK_NOTIFICATIONS } from '../constants';

interface LayoutProps {
  children: React.ReactNode;
  isAdmin: boolean;
  onToggleAdmin: () => void;
  coopName: string;
}

const Layout: React.FC<LayoutProps> = ({ children, isAdmin, onToggleAdmin, coopName }) => {
  const location = useLocation();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setIsProfileOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const navItems = [
    { label: 'Dashboard', path: '/', icon: 'fa-chart-line' },
    { label: 'Calendar', path: '/calendar', icon: 'fa-calendar-days' },
    { label: 'Committees', path: '/committees', icon: 'fa-users-gear' },
    { label: 'Maintenance', path: '/maintenance', icon: 'fa-tools' },
    { label: 'Documents', path: '/documents', icon: 'fa-file-lines' },
    { label: 'Finances', path: '/finances', icon: 'fa-wallet' },
    { label: 'Communications', path: '/communications', icon: 'fa-comments' },
    { label: 'Directory', path: '/directory', icon: 'fa-address-book' },
  ];

  if (isAdmin) {
    navItems.push(
      { label: 'Units', path: '/admin/units', icon: 'fa-house-chimney' },
      { label: 'Tenants', path: '/admin/tenants', icon: 'fa-users' },
      { label: 'Reports', path: '/admin/reports', icon: 'fa-chart-pie' }
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      {/* Sidebar Backdrop */}
      {isSidebarOpen && <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-40 lg:hidden" onClick={() => setIsSidebarOpen(false)} />}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white flex flex-col transition-transform duration-300 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} lg:relative lg:translate-x-0`}>
        <div className="p-6">
          <h1 className="text-xl font-bold flex items-center gap-2">
            <i className="fa-solid fa-house-signal text-emerald-400"></i>
            <span>{coopName}</span>
          </h1>
          <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-widest font-black">Co-op Management</p>
        </div>

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              onClick={() => setIsSidebarOpen(false)}
              className={`flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                location.pathname === item.path ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <i className={`fa-solid ${item.icon} w-5`}></i>
              <span className="text-sm font-bold">{item.label}</span>
            </Link>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <button onClick={() => { onToggleAdmin(); setIsSidebarOpen(false); }} className={`w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-xs font-black uppercase transition-all ${isAdmin ? 'bg-amber-500/10 text-amber-500 border border-amber-500/20' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
            <i className={`fa-solid ${isAdmin ? 'fa-user-shield' : 'fa-user'}`}></i>
            {isAdmin ? 'Admin Mode' : 'Switch to Admin'}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden w-full relative">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 lg:px-8 shadow-sm shrink-0 z-30">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 text-slate-500 hover:text-emerald-600">
              <i className="fa-solid fa-bars-staggered text-xl"></i>
            </button>
            <h2 className="text-sm lg:text-base font-black text-slate-800 uppercase tracking-tight truncate">
              {navItems.find(n => n.path === location.pathname)?.label || 'Portal'}
            </h2>
          </div>

          <div className="flex items-center gap-1 lg:gap-3">
            <button className="p-2 text-slate-400 hover:text-emerald-600 transition-colors hidden sm:block">
              <i className="fa-solid fa-magnifying-glass"></i>
            </button>

            {/* Notifications Button */}
            <button 
              onClick={() => setIsNotificationsOpen(true)}
              className="p-2 text-slate-400 hover:text-emerald-600 transition-colors relative"
            >
              <i className="fa-solid fa-bell"></i>
              <span className="absolute top-2 right-2 w-2 h-2 bg-rose-500 rounded-full border-2 border-white animate-pulse"></span>
            </button>

            {/* Profile Dropdown */}
            <div className="relative" ref={profileRef}>
              <button 
                onClick={() => setIsProfileOpen(!isProfileOpen)}
                className="flex items-center gap-2 pl-2 lg:pl-4 border-l border-slate-200 ml-2"
              >
                <div className="w-8 h-8 rounded-xl bg-emerald-500 flex items-center justify-center text-white font-black text-xs shadow-sm ring-2 ring-emerald-50">BC</div>
                <i className={`fa-solid fa-chevron-down text-[10px] text-slate-400 transition-transform ${isProfileOpen ? 'rotate-180' : ''}`}></i>
              </button>

              {isProfileOpen && (
                <div className="absolute right-0 mt-3 w-56 bg-white rounded-2xl shadow-2xl border border-slate-100 py-2 animate-in fade-in zoom-in-95 duration-100 overflow-hidden">
                  <div className="px-4 py-3 border-b border-slate-50 mb-1">
                    <p className="text-xs font-black text-slate-900">BC Resident</p>
                    <p className="text-[10px] text-slate-400 truncate">member@pcrest-coop.ca</p>
                  </div>
                  <button className="w-full text-left px-4 py-2.5 text-xs font-bold text-slate-600 hover:bg-slate-50 flex items-center gap-3">
                    <i className="fa-solid fa-gear text-slate-400"></i> Settings
                  </button>
                  <button className="w-full text-left px-4 py-2.5 text-xs font-bold text-slate-600 hover:bg-slate-50 flex items-center gap-3">
                    <i className="fa-solid fa-circle-info text-slate-400"></i> Co-op Info
                  </button>
                  <div className="border-t border-slate-50 mt-1">
                    <button className="w-full text-left px-4 py-2.5 text-xs font-bold text-rose-500 hover:bg-rose-50 flex items-center gap-3">
                      <i className="fa-solid fa-power-off"></i> Logout
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Notifications Slide-over */}
        {isNotificationsOpen && (
          <>
            <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-xs z-40 transition-opacity" onClick={() => setIsNotificationsOpen(false)} />
            <div className="fixed inset-y-0 right-0 w-full sm:w-96 bg-white z-50 shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col">
              <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <h3 className="font-black text-slate-900 uppercase tracking-widest text-xs">Activity Center</h3>
                <button onClick={() => setIsNotificationsOpen(false)} className="w-8 h-8 rounded-full hover:bg-slate-200 flex items-center justify-center transition-colors">
                  <i className="fa-solid fa-xmark text-slate-500"></i>
                </button>
              </div>
              <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {MOCK_NOTIFICATIONS.map(n => (
                  <div key={n.id} className={`p-4 rounded-2xl border transition-all hover:border-emerald-200 cursor-pointer group ${!n.isRead ? 'bg-emerald-50/30 border-emerald-100' : 'bg-white border-slate-100 opacity-70'}`}>
                    <div className="flex justify-between items-start mb-2">
                      <span className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter ${n.type === 'urgent' ? 'bg-rose-100 text-rose-700' : 'bg-blue-100 text-blue-700'}`}>
                        {n.type}
                      </span>
                      <span className="text-[9px] text-slate-400 font-bold uppercase">{n.timestamp}</span>
                    </div>
                    <h4 className="text-sm font-bold text-slate-800 mb-1 group-hover:text-emerald-700">{n.title}</h4>
                    <p className="text-xs text-slate-500 leading-relaxed">{n.body}</p>
                  </div>
                ))}
              </div>
              <div className="p-4 border-t border-slate-100">
                <button className="w-full bg-slate-900 text-white py-3 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-black transition-all">Mark All Read</button>
              </div>
            </div>
          </>
        )}

        <section className="flex-1 overflow-y-auto p-4 lg:p-8 bg-slate-50/50">
          {children}
        </section>
      </main>
    </div>
  );
};

export default Layout;

