              <Link to={`/admin/tenants/${tenant?.id}`} className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-xl group transition-all hover:bg-emerald-50 dark:hover:bg-emerald-900/20">
                <div className="w-10 h-10 bg-white dark:bg-slate-900 rounded-lg flex items-center justify-center text-slate-400 group-hover:text-emerald-600">
                  <i className="fa-solid fa-user"></i>
                </div>
