}

export interface MaintenanceNote {
  id: string;
  author: string;
  date: string;
  content: string;
}

export interface MaintenanceExpense {
  id: string;
  item: string;
  cost: number;
  date: string;
}

export interface Unit {
  id: string;
  number: string;
  type: '1BR' | '2BR' | '3BR' | '4BR';
  floor: number;
  currentTenantId?: string;
  status: 'Occupied' | 'Vacant' | 'Maintenance';
  lastInspectionDate?: string;
  ownerEmail?: string;
}

export interface ParticipationRecord {
  id: string;
  tenantId: string;
  date: string;
  hours: number;
  description: string;
  committeeId?: string;
}

export interface Tenant {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  unitId?: string;
  startDate: string;
  endDate?: string;
  status: 'Current' | 'Past' | 'Waitlist';
