}

export interface Announcement {
  id: string;
  title: string;
  content: string;
  author: string;
  date: string;
  priority: 'Normal' | 'Urgent';
}

export interface Message {
  id: string;
  fromId: string;
  toId: string;
  toCommitteeId?: string;
  body: string;
  timestamp: string;
}

export interface CoopEvent {
  id: string;
