        </Link>
        <span>/</span>
        <span className="font-semibold text-slate-800 dark:text-slate-200">Ticket #{request.id}</span>
      </div>

      {/* RAG Status Bar */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-6">
          <div className="flex flex-1 w-full gap-2 lg:gap-4 overflow-x-auto scrollbar-hide pb-2 sm:pb-0">
            {(Object.values(RequestStatus)).map((status) => {
              const isActive = request.status === status;
              return (
                <button
                  key={status}
                  onClick={() => handleStatusChange(status)}
                  className={`flex-1 min-w-[120px] py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    isActive 
                    ? `${getStatusColor(status)} shadow-lg scale-105 z-10` 
                    : 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-40 hover:opacity-60 grayscale'
                  }`}
