import React, { useState } from 'react';
import { MaintenanceRequest, RequestStatus, RepairQuote } from '../types';
import { MOCK_REQUESTS, MOCK_UNITS, MOCK_QUOTES } from '../constants';
import { geminiService } from '../services/geminiService';
import { useNavigate } from 'react-router-dom';

interface MaintenanceProps {
  isAdmin?: boolean;
}

const Maintenance: React.FC<MaintenanceProps> = ({ isAdmin = false }) => {
  const navigate = useNavigate();
  const [requests, setRequests] = useState<MaintenanceRequest[]>(MOCK_REQUESTS);
  const [quotes, setQuotes] = useState<RepairQuote[]>(MOCK_QUOTES);
  const [showForm, setShowForm] = useState(false);
  const [activeView, setActiveView] = useState<'requests' | 'quotes'>(isAdmin ? 'requests' : 'requests');
  const [selectedRequestIdForQuotes, setSelectedRequestIdForQuotes] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  // Form State
  const [description, setDescription] = useState('');
  const [unitId, setUnitId] = useState('');
  const [category, setCategory] = useState('Other');
  const [urgency, setUrgency] = useState('Low');

  const handleTriage = async () => {
    if (!description || description.length < 10) return;
    setLoading(true);
    try {
      const result = await geminiService.triageMaintenanceRequest(description);
      if (result.category) setCategory(result.category);
      if (result.urgency) setUrgency(result.urgency);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Fix: Added missing 'notes' and 'expenses' properties to comply with MaintenanceRequest interface
    const newRequest: MaintenanceRequest = {
      id: `r${Date.now()}`,
      unitId,
      tenantId: 't1', 
      category: category as any,
      description,
      urgency: urgency as any,
      status: RequestStatus.PENDING,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      notes: [],
      expenses: [],
      attachments: []
    };
    setRequests([newRequest, ...requests]);
    setShowForm(false);
    setDescription('');
    setUnitId('');
    alert("Maintenance request submitted successfully!");
  };

  const updateRequestStatus = (id: string, status: RequestStatus) => {
    setRequests(requests.map(r => r.id === id ? { ...r, status, updatedAt: new Date().toISOString() } : r));
  };

  const approveQuote = (quoteId: string) => {
    setQuotes(quotes.map(q => q.id === quoteId ? { ...q, status: 'Approved' } : q));
    alert("Quote approved. Vendor has been notified.");
  };

  const filteredQuotes = selectedRequestIdForQuotes 
    ? quotes.filter(q => q.requestId === selectedRequestIdForQuotes)
    : quotes;

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12 transition-colors duration-200">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800 dark:text-white">Maintenance & Operations</h2>
          <p className="text-slate-500 dark:text-slate-400 text-sm">Managing building longevity and member comfort.</p>
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          {isAdmin && (
            <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl flex-1 sm:flex-none shadow-inner">
              <button 
                onClick={() => { setActiveView('requests'); setSelectedRequestIdForQuotes(null); }}
