import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { MOCK_REQUESTS, MOCK_UNITS, MOCK_TENANTS, MOCK_QUOTES } from '../constants';
import { RequestStatus, MaintenanceNote, MaintenanceExpense } from '../types';

const MaintenanceDetail: React.FC = () => {
  const { requestId } = useParams<{ requestId: string }>();
  const navigate = useNavigate();
  const [request, setRequest] = useState(MOCK_REQUESTS.find(r => r.id === requestId));
  const unit = MOCK_UNITS.find(u => u.id === request?.unitId);
  const tenant = MOCK_TENANTS.find(t => t.id === request?.tenantId);
  const quotes = MOCK_QUOTES.filter(q => q.requestId === requestId);

  // States for interactive logging
  const [newNote, setNewNote] = useState('');
  const [newItem, setNewItem] = useState('');
  const [newCost, setNewCost] = useState('');

  if (!request) return <div className="p-12 text-center text-slate-500 font-bold">Maintenance ticket not found.</div>;

  const handleStatusChange = (status: RequestStatus) => {
    setRequest(prev => prev ? { ...prev, status, updatedAt: new Date().toISOString() } : undefined);
  };

  const addNote = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newNote.trim()) return;
    const note: MaintenanceNote = {
      id: `n${Date.now()}`,
      author: 'Kevin M. (Admin)',
      date: new Date().toISOString(),
      content: newNote.trim()
    };
    // Append at the beginning for reverse chronological order (newest at top)
    setRequest(prev => prev ? { ...prev, notes: [note, ...prev.notes] } : undefined);
    setNewNote('');
  };

  const addExpense = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim() || !newCost) return;
    const expense: MaintenanceExpense = {
      id: `ex${Date.now()}`,
      item: newItem.trim(),
      cost: parseFloat(newCost),
      date: new Date().toISOString().split('T')[0]
    };
    setRequest(prev => prev ? { ...prev, expenses: [...prev.expenses, expense] } : undefined);
    setNewItem('');
    setNewCost('');
  };

  // Color Mapping for Status (RAG)
  const getStatusColor = (status: RequestStatus) => {
    switch (status) {
      case RequestStatus.PENDING: return 'bg-amber-500 text-white ring-amber-500/30 shadow-amber-500/20';
      case RequestStatus.IN_PROGRESS: return 'bg-blue-500 text-white ring-blue-500/30 shadow-blue-500/20';
      case RequestStatus.COMPLETED: return 'bg-emerald-500 text-white ring-emerald-500/30 shadow-emerald-500/20';
      case RequestStatus.CANCELLED: return 'bg-rose-500 text-white ring-rose-500/30 shadow-rose-500/20';
      default: return 'bg-slate-300';
    }
  };

  // Color Mapping for Urgency (RAG)
  const getUrgencyColor = (urgency: string) => {
    switch (urgency) {
      case 'Emergency': return 'bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-900/40 dark:text-rose-400 dark:border-rose-800';
      case 'High': return 'bg-orange-100 text-orange-700 border-orange-200 dark:bg-orange-900/40 dark:text-orange-400 dark:border-orange-800';
      case 'Medium': return 'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/40 dark:text-amber-400 dark:border-amber-800';
      case 'Low': return 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/40 dark:text-emerald-400 dark:border-emerald-800';
      default: return 'bg-slate-100 text-slate-700 border-slate-200 dark:bg-slate-800 dark:text-slate-400';
    }
  };

  const totalExpenses = request.expenses.reduce((acc, curr) => acc + curr.cost, 0);

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12 transition-colors duration-200">
      {/* Navigation Breadcrumbs */}
      <div className="flex items-center gap-4 text-slate-500 text-sm mb-2">
        <Link to="/maintenance" className="hover:text-emerald-600 transition-colors flex items-center gap-1 font-bold">
          <i className="fa-solid fa-arrow-left"></i> Maintenance Queue
        </Link>
        <span>/</span>
        <span className="font-semibold text-slate-800 dark:text-slate-200">Ticket #{request.id}</span>
      </div>

      {/* RAG Status Bar - Fixed scroll issues and responsive wrap */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
        <div className="flex flex-col lg:flex-row items-center justify-between gap-6">
          <div className="grid grid-cols-2 sm:grid-cols-4 w-full gap-3">
            {(Object.values(RequestStatus)).map((status) => {
              const isActive = request.status === status;
              return (
                <button
                  key={status}
                  onClick={() => handleStatusChange(status)}
                  className={`py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    isActive 
                    ? `${getStatusColor(status)} shadow-lg scale-105 z-10 ring-2` 
                    : 'bg-slate-50 dark:bg-slate-800/50 text-slate-400 dark:text-slate-600 opacity-60 hover:opacity-100'
                  }`}
                >
                  {status}
                </button>
              );
            })}
          </div>
          <div className="flex flex-col items-center lg:items-end shrink-0 w-full lg:w-auto">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Last Update</p>
            <p className="text-xs font-bold text-slate-700 dark:text-slate-300">{new Date(request.updatedAt).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' })}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          {/* Main Info */}
          <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-[0.03] text-8xl pointer-events-none">
              <i className="fa-solid fa-toolbox"></i>
            </div>
            <div className="relative z-10">
              <span className={`text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border shadow-sm ${getUrgencyColor(request.urgency)}`}>
                <i className="fa-solid fa-triangle-exclamation mr-2"></i>
                {request.urgency} Urgency
              </span>
              <h1 className="text-3xl font-black text-slate-900 dark:text-white mt-8 leading-tight">{request.category}: {request.description}</h1>
              <p className="text-slate-500 dark:text-slate-400 text-sm mt-4 flex items-center gap-3">
                <i className="fa-solid fa-calendar-plus opacity-30"></i> 
                Opened on {new Date(request.createdAt).toLocaleString()} by 
                <Link to={`/admin/tenants/${tenant?.id}`} className="text-emerald-600 font-bold hover:underline">
                  {tenant?.firstName} {tenant?.lastName}
                </Link>
              </p>
            </div>
          </section>

          {/* Chronological Note Feed */}
          <section className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 dark:border-white/5 bg-slate-50/50 dark:bg-slate-950/50 flex justify-between items-center">
              <h3 className="font-black text-slate-800 dark:text-white uppercase tracking-widest text-xs">Activity Log & Admin Notes</h3>
              <span className="text-[10px] font-bold text-slate-400">Reverse Chronological</span>
            </div>
            <div className="p-6 space-y-6">
              {/* Add Note Form */}
              <form onSubmit={addNote} className="relative mb-8">
                <textarea
                  className="w-full bg-slate-50 dark:bg-slate-950/50 border border-slate-200 dark:border-white/10 rounded-2xl p-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-all min-h-[100px] text-slate-800 dark:text-slate-200 shadow-inner"
                  placeholder="Record an update or internal memo..."
                  value={newNote}
                  onChange={(e) => setNewNote(e.target.value)}
                />
                <button 
