              </form>

              {/* Feed Items */}
              <div className="space-y-6">
                {request.notes.map((note, index) => (
                  <div key={note.id} className="flex gap-4 group">
                    <div className="flex flex-col items-center">
                      <div className="w-8 h-8 rounded-xl bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-400 text-xs font-black shadow-sm group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 transition-colors">
