    e.preventDefault();
    if (!newNote.trim()) return;
    const note: MaintenanceNote = {
      id: `n${Date.now()}`,
      author: 'Kevin M. (Admin)',
      date: new Date().toISOString(),
      content: newNote.trim()
    };
