import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { MOCK_REQUESTS, MOCK_UNITS, MOCK_TENANTS } from '../constants';
import { RequestStatus, MaintenanceNote, MaintenanceExpense } from '../types';

const MaintenanceDetail: React.FC = () => {
  const { requestId } = useParams<{ requestId: string }>();
  const navigate = useNavigate();
  const [request, setRequest] = useState(MOCK_REQUESTS.find(r => r.id === requestId));
  const unit = MOCK_UNITS.find(u => u.id === request?.unitId);
  const tenant = MOCK_TENANTS.find(t => t.id === request?.tenantId);

  // States for interactive logging
  const [newNote, setNewNote] = useState('');
  const [newItem, setNewItem] = useState('');
  const [newCost, setNewCost] = useState('');

  // Re-open States
  const [showReopenModal, setShowReopenModal] = useState(false);
  const [reopenReason, setReopenReason] = useState('');

  if (!request) return <div className="p-12 text-center text-slate-500 font-bold">Maintenance ticket not found.</div>;

  const isLocked = request.status === RequestStatus.COMPLETED || request.status === RequestStatus.CANCELLED;

  const handleStatusChange = (status: RequestStatus) => {
    if (isLocked) return;
    setRequest(prev => prev ? { ...prev, status, updatedAt: new Date().toISOString() } : undefined);
  };

  const addNote = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newNote.trim() || isLocked) return;
    const note: MaintenanceNote = {
      id: `n${Date.now()}`,
      author: 'Kevin M. (Admin)',
      date: new Date().toISOString(),
      content: newNote.trim()
    };
    setRequest(prev => prev ? { ...prev, notes: [...prev.notes, note] } : undefined);
    setNewNote('');
  };

  const handleReopen = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reopenReason.trim()) return;

    const systemNote: MaintenanceNote = {
      id: `sys-${Date.now()}`,
      author: 'SYSTEM (Admin Action)',
      date: new Date().toISOString(),
      content: `CASE RE-OPENED. Reason: ${reopenReason}`
    };

    setRequest(prev => prev ? { 
      ...prev, 
      status: RequestStatus.IN_PROGRESS, 
      updatedAt: new Date().toISOString(),
      notes: [...prev.notes, systemNote]
    } : undefined);

    setShowReopenModal(false);
    setReopenReason('');
    alert("Ticket has been moved back to Active Status.");
  };

  const addExpense = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim() || !newCost || isLocked) return;
    const expense: MaintenanceExpense = {
      id: `ex${Date.now()}`,
      item: newItem.trim(),
      cost: parseFloat(newCost),
      date: new Date().toISOString().split('T')[0]
    };
    setRequest(prev => prev ? { ...prev, expenses: [...prev.expenses, expense] } : undefined);
    setNewItem('');
    setNewCost('');
  };

  const getStatusColor = (status: RequestStatus) => {
    switch (status) {
      case RequestStatus.PENDING: return 'bg-amber-500 text-white ring-amber-500/30 shadow-amber-500/20';
      case RequestStatus.IN_PROGRESS: return 'bg-blue-500 text-white ring-blue-500/30 shadow-blue-500/20';
      case RequestStatus.COMPLETED: return 'bg-emerald-500 text-white ring-emerald-500/30 shadow-emerald-500/20';
      case RequestStatus.CANCELLED: return 'bg-rose-500 text-white ring-rose-500/30 shadow-rose-500/20';
      default: return 'bg-slate-300';
    }
  };

  const getUrgencyColor = (urgency: string) => {
    switch (urgency) {
      case 'Emergency': return 'bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-900/40 dark:text-rose-400 dark:border-rose-800';
      case 'High': return 'bg-orange-100 text-orange-700 border-orange-200 dark:bg-orange-900/40 dark:text-orange-400 dark:border-orange-800';
      case 'Medium': return 'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/40 dark:text-amber-400 dark:border-amber-800';
      case 'Low': return 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/40 dark:text-emerald-400 dark:border-emerald-800';
      default: return 'bg-slate-100 text-slate-700 border-slate-200 dark:bg-slate-800 dark:text-slate-400';
    }
  };

  const totalExpenses = request.expenses.reduce((acc, curr) => acc + curr.cost, 0);

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12 transition-colors duration-200">
      <div className="flex items-center justify-between gap-4 text-slate-500 text-sm mb-2">
        <div className="flex items-center gap-4">
          <Link to="/maintenance" className="hover:text-emerald-600 transition-colors flex items-center gap-1 font-bold">
            <i className="fa-solid fa-arrow-left"></i> Maintenance Queue
          </Link>
          <span>/</span>
          <span className="font-semibold text-slate-800 dark:text-slate-200">Ticket #{request.id}</span>
        </div>
        {isLocked && (
          <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
            <i className="fa-solid fa-lock"></i> Record Finalized
          </span>
        )}
      </div>

      {/* RAG Status Bar */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
        <div className="flex flex-col lg:flex-row items-center justify-between gap-6">
          <div className="grid grid-cols-2 sm:grid-cols-4 w-full gap-3">
            {(Object.values(RequestStatus)).map((status) => {
              const isActive = request.status === status;
              return (
                <button
                  key={status}
                  disabled={isLocked && !isActive}
                  onClick={() => handleStatusChange(status)}
                  className={`py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    isActive 
                    ? `${getStatusColor(status)} shadow-lg scale-105 z-10 ring-2` 
                    : isLocked
                      ? 'bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-700 cursor-not-allowed opacity-30'
                      : 'bg-slate-50 dark:bg-slate-800/50 text-slate-400 dark:text-slate-600 opacity-60 hover:opacity-100'
                  }`}
                >
                  {status}
                </button>
              );
            })}
          </div>
          <div className="flex flex-col items-center lg:items-end shrink-0 w-full lg:w-auto">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Status Effective</p>
            <p className="text-xs font-bold text-slate-700 dark:text-slate-300 whitespace-nowrap">{new Date(request.updatedAt).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' })}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          {/* Detailed Request Header */}
          <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-[0.03] text-8xl pointer-events-none">
              <i className="fa-solid fa-toolbox"></i>
            </div>
            <div className="relative z-10">
              <div className="flex flex-wrap gap-3 items-center mb-6">
                <span className={`text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border shadow-sm ${getUrgencyColor(request.urgency)}`}>
                  <i className="fa-solid fa-triangle-exclamation mr-2"></i>
                  {request.urgency} Urgency
                </span>
                <span className="text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-300">
                  <i className="fa-solid fa-tags mr-2"></i>
                  {request.category}
                </span>
              </div>

              <h1 className="text-4xl font-black text-slate-900 dark:text-white leading-tight">
                {request.description}
              </h1>

              <div className="mt-8 grid grid-cols-1 sm:grid-cols-2 gap-6 pt-8 border-t border-slate-50 dark:border-white/5">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-400">
                    <i className="fa-solid fa-door-open text-xl"></i>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Location</p>
                    <Link to={`/admin/units/${unit?.id}?tab=maintenance`} className="text-sm font-black text-slate-800 dark:text-slate-200 hover:text-emerald-600 transition-colors">
                      Unit #{unit?.number}
                    </Link>
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-400">
                    <i className="fa-solid fa-user-circle text-xl"></i>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Submitted By</p>
                    <Link to={`/admin/tenants/${tenant?.id}`} className="text-sm font-black text-slate-800 dark:text-slate-200 hover:text-emerald-600 transition-colors">
                      {tenant?.firstName} {tenant?.lastName}
                    </Link>
                  </div>
                </div>
              </div>
            </div>
          </section>

          {/* Activity Log (Notes first, then input) */}
          <section className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 dark:border-white/5 bg-slate-50/50 dark:bg-slate-950/50 flex justify-between items-center">
              <h3 className="font-black text-slate-800 dark:text-white uppercase tracking-widest text-xs">Activity Log & Historical Notes</h3>
              <span className="text-[10px] font-bold text-slate-400">Chronological Record</span>
            </div>

            <div className="p-6 space-y-8">
              {/* Existing Feed Items */}
              <div className="space-y-6">
                {request.notes.map((note, index) => (
                  <div key={note.id} className="flex gap-4 group">
                    <div className="flex flex-col items-center">
                      <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs font-black shadow-sm transition-colors ${
                        note.author.includes('SYSTEM') 
                          ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/40 dark:text-rose-400' 
                          : 'bg-slate-100 dark:bg-slate-800 text-slate-400 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20'
                      }`}>
                        {note.author.includes('SYSTEM') ? <i className="fa-solid fa-shield-halved"></i> : note.author[0]}
                      </div>
                      <div className="w-px h-full bg-slate-100 dark:bg-slate-800 mt-2"></div>
                    </div>
                    <div className="flex-1 pb-4">
                      <div className="flex justify-between items-start mb-1">
                        <p className={`text-sm font-black ${note.author.includes('SYSTEM') ? 'text-rose-600 dark:text-rose-400' : 'text-slate-800 dark:text-white'}`}>{note.author}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(note.date).toLocaleString([], { dateStyle: 'short', timeStyle: 'short' })}</p>
                      </div>
                      <p className={`text-sm leading-relaxed font-medium ${note.author.includes('SYSTEM') ? 'text-rose-500 italic' : 'text-slate-600 dark:text-slate-400'}`}>
                        {note.content}
                      </p>
                    </div>
                  </div>
                ))}
                {request.notes.length === 0 && (
                  <p className="text-center py-8 text-xs text-slate-400 italic font-medium">No activity notes recorded.</p>
                )}
              </div>

              {/* Add Note Form - Only for Active Tickets */}
              {!isLocked ? (
                <div className="pt-8 border-t border-slate-50 dark:border-white/5">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Post New Update</h4>
                  <form onSubmit={addNote} className="relative">
                    <textarea
                      className="w-full bg-slate-50 dark:bg-slate-950/50 border border-slate-200 dark:border-white/10 rounded-2xl p-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-all min-h-[120px] text-slate-800 dark:text-slate-200 shadow-inner"
                      placeholder="Detail follow-up actions, progress, or memo..."
                      value={newNote}
                      onChange={(e) => setNewNote(e.target.value)}
                    />
                    <button 
                      type="submit"
                      className="absolute bottom-4 right-4 bg-slate-900 dark:bg-emerald-600 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all"
                    >
                      Log Update
                    </button>
                  </form>
                </div>
              ) : (
                <div className="p-4 bg-slate-50 dark:bg-slate-950/50 border border-dashed border-slate-200 dark:border-white/10 rounded-2xl text-center">
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Case Archived • Update Posting Disabled</p>
                </div>
              )}
            </div>
          </section>

          {/* Internal Expenses */}
          <section className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 dark:border-white/5 bg-slate-50/50 dark:bg-slate-950/50 flex justify-between items-center">
              <h3 className="font-black text-slate-800 dark:text-white uppercase tracking-widest text-xs">Cost Ledger</h3>
              <div className="text-right">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Total Investment</p>
                <p className="text-sm font-black text-emerald-600 dark:text-emerald-400">${totalExpenses.toFixed(2)}</p>
              </div>
            </div>

            <div className="p-6">
              {!isLocked && (
                <form onSubmit={addExpense} className="grid grid-cols-1 sm:grid-cols-4 gap-4 mb-8 p-4 bg-slate-50 dark:bg-slate-950/50 rounded-2xl border border-slate-100 dark:border-white/5">
                  <div className="sm:col-span-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Item Description</label>
                    <input 
                      type="text" 
                      className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-emerald-500"
                      placeholder="e.g. Parts, Supplies"
                      value={newItem}
                      onChange={(e) => setNewItem(e.target.value)}
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Cost ($)</label>
                    <input 
                      type="number" 
                      step="0.01"
                      className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-emerald-500"
                      placeholder="0.00"
                      value={newCost}
                      onChange={(e) => setNewCost(e.target.value)}
                    />
                  </div>
                  <div className="flex items-end">
                    <button type="submit" className="w-full bg-emerald-600 text-white h-[38px] rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all">
                      Add
                    </button>
                  </div>
                </form>
              )}

              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <tbody className="divide-y divide-slate-50 dark:divide-white/5">
                    {request.expenses.map(ex => (
                      <tr key={ex.id}>
                        <td className="py-4 text-xs font-bold text-slate-500">{ex.date}</td>
                        <td className="py-4 text-sm font-black text-slate-800 dark:text-slate-200">{ex.item}</td>
                        <td className="py-4 text-sm font-black text-slate-900 dark:text-white text-right">${ex.cost.toFixed(2)}</td>
                      </tr>
                    ))}
                    {request.expenses.length === 0 && (
                      <tr>
                        <td colSpan={3} className="py-8 text-center text-xs text-slate-400 italic">No costs logged.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </section>
        </div>

        {/* Sidebar Actions */}
        <div className="space-y-6">
          {/* Admin Contextual Meta */}
          <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
            <h3 className="font-black text-slate-900 dark:text-white uppercase tracking-widest text-[10px] mb-6 border-b border-slate-50 dark:border-white/5 pb-4">Incident Background</h3>
            <div className="space-y-4">
              <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-transparent">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Unit Status</p>
                  <p className="text-sm font-black text-slate-800 dark:text-slate-200">{unit?.status} • {unit?.type}</p>
              </div>
              <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-transparent">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Member Tenure</p>
                  <p className="text-sm font-black text-slate-800 dark:text-slate-200">
                    Resident since {tenant ? new Date(tenant.startDate).getFullYear() : 'N/A'}
                  </p>
              </div>
              <Link to={`/admin/units/${unit?.id}?tab=maintenance`} className="flex items-center justify-between p-3 bg-emerald-50 dark:bg-emerald-900/20 rounded-xl hover:bg-emerald-100 transition-all border border-emerald-100 dark:border-emerald-800 group">
                <span className="text-xs font-black text-emerald-700 dark:text-emerald-400 uppercase">View Unit History</span>
                <i className="fa-solid fa-arrow-right text-[10px] text-emerald-600 group-hover:translate-x-1 transition-transform"></i>
              </Link>
            </div>
          </div>

          {/* Lifecycle Actions */}
          <div className="bg-slate-900 dark:bg-slate-950 p-8 rounded-3xl shadow-xl border border-white/5">
             <h3 className="text-emerald-400 font-black uppercase text-[10px] tracking-widest mb-6">Management Panel</h3>
             <div className="space-y-3">
                {request.status === RequestStatus.COMPLETED && (
                  <button 
                    onClick={() => window.print()} 
                    className="w-full p-4 bg-emerald-600 text-white rounded-2xl flex items-center justify-center gap-3 hover:bg-emerald-700 transition-all shadow-lg active:scale-95 group"
                  >
                    <i className="fa-solid fa-print group-hover:scale-110 transition-transform"></i>
                    <span className="text-[10px] font-black uppercase tracking-widest">Print Work Order</span>
                  </button>
                )}

                {isLocked && (
                  <button 
                    onClick={() => setShowReopenModal(true)}
                    className="w-full p-4 bg-white/10 border border-white/20 rounded-2xl flex items-center justify-center gap-3 hover:bg-white/20 transition-all group"
                  >
                    <i className="fa-solid fa-rotate-left text-amber-400 group-hover:rotate-[-45deg] transition-transform"></i>
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">Re-open Ticket</span>
                  </button>
                )}

                <button 
                  onClick={() => alert("Resident notification re-dispatched.")} 
                  className="w-full p-4 bg-white/5 border border-white/10 rounded-2xl flex items-center justify-center gap-3 hover:bg-white/10 transition-colors"
                >
                  <i className="fa-solid fa-paper-plane text-blue-400"></i>
                  <span className="text-[10px] font-black text-white uppercase tracking-widest">Notify Resident</span>
                </button>
             </div>
          </div>
        </div>
      </div>

      {/* Re-open Modal */}
      {showReopenModal && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-slate-900 dark:text-white flex items-center gap-3">
                  <i className="fa-solid fa-rotate-left text-amber-500"></i>
                  Re-open Archive
                </h3>
                <button onClick={() => setShowReopenModal(false)} className="text-slate-400 hover:text-slate-600"><i className="fa-solid fa-xmark"></i></button>
             </div>
             <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 font-medium leading-relaxed">
               Finalized tickets should only be re-opened if the repair was unsatisfactory or has recurred. A mandatory reason is required for the audit log.
             </p>
             <form onSubmit={handleReopen} className="space-y-4">
                <textarea 
                  required
                  className="w-full bg-slate-50 dark:bg-slate-950/50 border border-slate-200 dark:border-white/10 rounded-2xl p-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-all min-h-[100px] text-slate-800 dark:text-slate-200 shadow-inner"
                  placeholder="Reason for re-opening (e.g. Seal failed after 48h)..."
                  value={reopenReason}
                  onChange={(e) => setReopenReason(e.target.value)}
                />
                <div className="flex gap-3">
                   <button type="button" onClick={() => setShowReopenModal(false)} className="flex-1 py-3 text-xs font-black uppercase text-slate-500 hover:bg-slate-50 rounded-xl">Cancel</button>
                   <button type="submit" className="flex-1 py-3 bg-emerald-600 text-white rounded-xl text-xs font-black uppercase shadow-lg hover:bg-emerald-700">Restore Ticket</button>
                </div>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

