                      className="text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-300 shadow-sm transition-transform active:scale-95 hover:brightness-95"
                    >
                      <i className="fa-solid fa-tags mr-2"></i>
