                    </button>
                  ))}
                  {request.category.length === 0 && (
                    <button 
                      onClick={() => setIsEditingCategories(!isEditingCategories)}
                      className="text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-dashed border-slate-300 dark:border-slate-700 text-slate-400"
                    >
                      + Add Category
                    </button>
                  )}
                  {isEditingCategories && (
                    <div className="absolute top-full left-0 mt-2 w-56 bg-white dark:bg-slate-800 border border-slate-200 dark:border-white/10 rounded-2xl shadow-2xl z-50 p-3 animate-in fade-in slide-in-from-top-2">
                       <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 px-1">Toggle Categories</p>
                       <div className="space-y-1">
                          {availableCategories.map(cat => (
