                       <button 
                        onClick={() => setIsEditingCategories(false)}
                        className="w-full mt-3 py-2 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest"
                       >
                         Done
                       </button>
                    </div>
                  )}
                </div>
              </div>

              <h1 className="text-4xl font-black text-slate-900 dark:text-white leading-tight">
                {request.description}
              </h1>

              <div className="mt-8 grid grid-cols-1 sm:grid-cols-2 gap-6 pt-8 border-t border-slate-50 dark:border-white/5">
                <Link to={`/admin/units/${unit?.id}?tab=maintenance`} className="flex items-center gap-4 group p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-transparent hover:border-emerald-200 dark:hover:border-emerald-800 transition-all active:scale-95 shadow-sm">
                  <div className="w-14 h-14 bg-white dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-emerald-600 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 shadow-inner transition-colors">
                    <i className="fa-solid fa-door-open text-2xl"></i>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Location Details</p>
                    <p className="text-lg font-black text-slate-800 dark:text-slate-200 group-hover:text-emerald-600 transition-colors">
                      Unit #{unit?.number}
                    </p>
                  </div>
                </Link>
                <Link to={`/admin/tenants/${tenant?.id}`} className="flex items-center gap-4 group p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-transparent hover:border-emerald-200 dark:hover:border-emerald-800 transition-all active:scale-95 shadow-sm">
                  <div className="w-14 h-14 bg-white dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-emerald-600 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 shadow-inner transition-colors">
                    <i className="fa-solid fa-user-circle text-2xl"></i>
