                      className="w-full bg-slate-50 dark:bg-slate-950/50 border border-slate-200 dark:border-white/10 rounded-2xl p-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-all min-h-[120px] text-slate-800 dark:text-slate-200 shadow-inner"
