                >
                  <i className="fa-solid fa-paper-plane text-blue-400"></i>
                  <span className="text-[10px] font-black text-white uppercase tracking-widest">Notify Resident</span>
                </button>
             </div>
          </div>
        </div>
      </div>

      {/* FIXED Multi-select Category Pop-up */}
      {isEditingCategories && (
        <div 
          className="fixed inset-0 z-[100] flex items-center justify-center p-4 sm:p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200"
          onClick={() => setIsEditingCategories(false)}
        >
          <div 
            className="bg-white dark:bg-slate-900 w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200 border border-slate-200 dark:border-white/5 flex flex-col max-h-[90vh]"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex justify-between items-center mb-6 shrink-0">
              <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Edit Categories</h3>
              <button onClick={() => setIsEditingCategories(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                <i className="fa-solid fa-xmark text-lg"></i>
              </button>
            </div>

            <p className="text-xs text-slate-500 dark:text-slate-400 mb-6 font-medium shrink-0">Select all applicable categories for this issue. This helps with reporting and dispatching.</p>

            <div className="space-y-1.5 overflow-y-auto pr-2 scrollbar-hide flex-1">
              {availableCategories.map(cat => {
                const isSelected = request.category.includes(cat);
                return (
                  <button 
                    key={cat} 
                    onClick={() => toggleCategory(cat)}
                    className={`w-full flex items-center justify-between px-5 py-3.5 text-xs font-black uppercase rounded-2xl transition-all ${
                      isSelected 
                        ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 scale-[1.02]' 
                        : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-500'
                    }`}
                  >
                    <span>{cat}</span>
                    {isSelected && <i className="fa-solid fa-check"></i>}
                  </button>
                );
              })}
            </div>

            <button 
              onClick={() => setIsEditingCategories(false)}
              className="w-full mt-8 py-4 bg-slate-900 dark:bg-emerald-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all shrink-0"
            >
              Done & Save
            </button>
          </div>
        </div>
      )}

      {/* Re-open Modal */}
      {showReopenModal && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-slate-900 dark:text-white flex items-center gap-3">
                  <i className="fa-solid fa-rotate-left text-amber-500"></i>
                  Re-open Archive
                </h3>
                <button onClick={() => setShowReopenModal(false)} className="text-slate-400 hover:text-slate-600"><i className="fa-solid fa-xmark"></i></button>
             </div>
             <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 font-medium leading-relaxed">
               Finalized tickets should only be re-opened if the repair was unsatisfactory or has recurred. A mandatory reason is required for the audit log.
             </p>
             <form onSubmit={handleReopen} className="space-y-4">
                <textarea 
                  required
                  className="w-full bg-slate-50 dark:bg-slate-950/50 border border-slate-200 dark:border-white/10 rounded-2xl p-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-all min-h-[100px] text-slate-800 dark:text-slate-200 shadow-inner"
                  placeholder="Reason for re-opening (e.g. Seal failed after 48h)..."
                  value={reopenReason}
                  onChange={(e) => setReopenReason(e.target.value)}
                />
                <div className="flex gap-3">
                   <button type="button" onClick={() => setShowReopenModal(false)} className="flex-1 py-3 text-xs font-black uppercase text-slate-500 hover:bg-slate-50 rounded-xl">Cancel</button>
                   <button type="submit" className="flex-1 py-3 bg-emerald-600 text-white rounded-xl text-xs font-black uppercase shadow-lg hover:bg-emerald-700">Restore Ticket</button>
                </div>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

