import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { MOCK_REQUESTS, MOCK_UNITS, MOCK_TENANTS } from '../constants';
import { RequestStatus, MaintenanceNote, MaintenanceExpense, MaintenanceCategory, MaintenanceRequest } from '../types';

const MaintenanceDetail: React.FC = () => {
  const { requestId } = useParams<{ requestId: string }>();
  const navigate = useNavigate();
  const [request, setRequest] = useState(MOCK_REQUESTS.find(r => r.id === requestId));
  const unit = MOCK_UNITS.find(u => u.id === request?.unitId);
  const tenant = MOCK_TENANTS.find(t => t.id === request?.tenantId);

  const [newNote, setNewNote] = useState('');
  const [newItem, setNewItem] = useState('');
  const [newCost, setNewCost] = useState('');
  const [isEditingUrgency, setIsEditingUrgency] = useState(false);
  const [isEditingCategories, setIsEditingCategories] = useState(false);
  const [showReopenModal, setShowReopenModal] = useState(false);
  const [reopenReason, setReopenReason] = useState('');

  if (!request) return <div className="p-12 text-center text-slate-500 font-bold">Maintenance ticket not found.</div>;

  const isLocked = request.status === RequestStatus.COMPLETED || request.status === RequestStatus.CANCELLED;

  const handleStatusChange = (status: RequestStatus) => {
    if (isLocked) return;
    setRequest(prev => prev ? { ...prev, status, updatedAt: new Date().toISOString() } : undefined);
  };

  const updateUrgency = (urgency: MaintenanceRequest['urgency']) => {
    setRequest(prev => prev ? { ...prev, urgency, updatedAt: new Date().toISOString() } : undefined);
    setIsEditingUrgency(false);
  };

  const toggleCategory = (cat: MaintenanceCategory) => {
    setRequest(prev => {
      if (!prev) return undefined;
      const current = prev.category;
      const next = current.includes(cat) 
        ? current.filter(c => c !== cat) 
        : [...current, cat];
      return { ...prev, category: next, updatedAt: new Date().toISOString() };
    });
  };

  const addNote = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newNote.trim() || isLocked) return;
    const note: MaintenanceNote = {
      id: `n${Date.now()}`,
      author: 'Kevin M. (Admin)',
      date: new Date().toISOString(),
      content: newNote.trim()
    };
    setRequest(prev => prev ? { ...prev, notes: [...prev.notes, note] } : undefined);
    setNewNote('');
  };

  const handleReopen = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reopenReason.trim()) return;
    const systemNote: MaintenanceNote = {
      id: `sys-${Date.now()}`,
      author: 'SYSTEM (Admin Action)',
      date: new Date().toISOString(),
      content: `CASE RE-OPENED. Reason: ${reopenReason}`
    };
    setRequest(prev => prev ? { 
      ...prev, 
      status: RequestStatus.IN_PROGRESS, 
      updatedAt: new Date().toISOString(),
      notes: [...prev.notes, systemNote]
    } : undefined);
    setShowReopenModal(false);
    setReopenReason('');
  };

  const addExpense = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim() || !newCost || isLocked) return;
    const expense: MaintenanceExpense = {
      id: `ex${Date.now()}`,
      item: newItem.trim(),
      cost: parseFloat(newCost),
      date: new Date().toISOString().split('T')[0]
    };
    setRequest(prev => prev ? { ...prev, expenses: [...prev.expenses, expense] } : undefined);
    setNewItem('');
    setNewCost('');
  };

  const getStatusColor = (status: RequestStatus) => {
    switch (status) {
      case RequestStatus.PENDING: return 'bg-amber-500 text-white ring-amber-500/30';
      case RequestStatus.IN_PROGRESS: return 'bg-blue-500 text-white ring-blue-500/30';
      case RequestStatus.COMPLETED: return 'bg-emerald-500 text-white ring-emerald-500/30';
      case RequestStatus.CANCELLED: return 'bg-rose-500 text-white ring-rose-500/30';
      default: return 'bg-slate-300';
    }
  };

