import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { MOCK_REQUESTS, MOCK_UNITS, MOCK_TENANTS } from '../constants';
import { RequestStatus, MaintenanceNote, MaintenanceExpense, MaintenanceCategory, MaintenanceRequest } from '../types';

const MaintenanceDetail: React.FC = () => {
  const { requestId } = useParams<{ requestId: string }>();
  const navigate = useNavigate();
  const [request, setRequest] = useState(MOCK_REQUESTS.find(r => r.id === requestId));
  const unit = MOCK_UNITS.find(u => u.id === request?.unitId);
  const tenant = MOCK_TENANTS.find(t => t.id === request?.tenantId);

  const [newNote, setNewNote] = useState('');
  const [isEditingCategories, setIsEditingCategories] = useState(false);
  const [showReopenModal, setShowReopenModal] = useState(false);
  const [reopenReason, setReopenReason] = useState('');

  if (!request) return <div className="p-12 text-center text-slate-500 font-bold">Ticket not found in archive.</div>;

  const isLocked = request.status === RequestStatus.COMPLETED || request.status === RequestStatus.CANCELLED;

  const handleStatusChange = (status: RequestStatus) => {
    if (isLocked) return;
    setRequest(prev => prev ? { ...prev, status, updatedAt: new Date().toISOString() } : undefined);
  };

  const toggleCategory = (cat: MaintenanceCategory) => {
    setRequest(prev => {
      if (!prev) return undefined;
      const current = prev.category;
      const next = current.includes(cat) ? current.filter(c => c !== cat) : [...current, cat];
      return { ...prev, category: next, updatedAt: new Date().toISOString() };
    });
  };

  const handleReopen = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reopenReason.trim()) return;
    setRequest(prev => prev ? { ...prev, status: RequestStatus.IN_PROGRESS, updatedAt: new Date().toISOString() } : undefined);
    setShowReopenModal(false);
    setReopenReason('');
  };

  const getStatusColor = (status: RequestStatus) => {
    switch (status) {
      case RequestStatus.PENDING: return 'bg-amber-500 text-white shadow-amber-500/20';
      case RequestStatus.IN_PROGRESS: return 'bg-blue-500 text-white shadow-blue-500/20';
      case RequestStatus.COMPLETED: return 'bg-emerald-500 text-white shadow-emerald-500/20';
      case RequestStatus.CANCELLED: return 'bg-rose-500 text-white shadow-rose-500/20';
      default: return 'bg-slate-300';
    }
  };

  const availableCategories: MaintenanceCategory[] = ['Plumbing', 'Electrical', 'Structural', 'Appliance', 'HVAC', 'Exterior', 'Safety', 'Other'];

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12 transition-colors duration-200">
      <div className="flex items-center justify-between gap-4 text-slate-500 text-sm mb-2">
        <div className="flex items-center gap-4">
          <Link to="/maintenance" className="hover:text-emerald-600 transition-colors flex items-center gap-1 font-bold">
            <i className="fa-solid fa-arrow-left"></i> Maintenance Queue
          </Link>
          <span>/</span>
          <span className="font-semibold text-slate-800 dark:text-slate-200">Ticket #{request.id}</span>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
        <div className="grid grid-cols-2 sm:grid-cols-4 w-full gap-3">
          {(Object.values(RequestStatus)).map((status) => {
            const isActive = request.status === status;
            return (
              <button
                key={status}
                disabled={isLocked && !isActive}
                onClick={() => handleStatusChange(status)}
                className={`py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  isActive ? `${getStatusColor(status)} shadow-lg scale-105 z-10` : 'bg-slate-50 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-60 hover:opacity-100'
                }`}
              >
                {status}
              </button>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm relative">
            <div className="relative z-10">
              <div className="flex flex-wrap gap-2 mb-6">
                {request.category.map(cat => (
                  <button 
                    key={cat}
                    disabled={isLocked}
                    onClick={() => setIsEditingCategories(true)}
                    className="text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:brightness-95 transition-all"
                  >
                    <i className="fa-solid fa-tag mr-2"></i>{cat}
                  </button>
                ))}
                {!isLocked && <button onClick={() => setIsEditingCategories(true)} className="text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-dashed border-slate-300 text-slate-400 hover:border-emerald-500 transition-colors">+ Edit Service Type</button>}
              </div>
              <h1 className="text-4xl font-black text-slate-900 dark:text-white leading-tight mb-8">{request.description}</h1>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-8 border-t border-slate-50 dark:border-white/5">
                <Link to={`/admin/units/${unit?.id}`} className="flex items-center gap-4 group p-5 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-transparent hover:border-emerald-500 transition-all">
                  <div className="w-14 h-14 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-emerald-500 shadow-inner transition-colors">
                    <i className="fa-solid fa-door-open text-2xl"></i>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Asset Location</p>
                    <p className="text-xl font-black text-slate-800 dark:text-slate-200 group-hover:text-emerald-600 transition-colors">Unit #{unit?.number}</p>
                  </div>
                </Link>
                <Link to={`/admin/tenants/${tenant?.id}`} className="flex items-center gap-4 group p-5 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-transparent hover:border-emerald-500 transition-all">
                  <div className="w-14 h-14 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-emerald-500 shadow-inner transition-colors">
                    <i className="fa-solid fa-user-circle text-2xl"></i>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Submitted By</p>
                    <p className="text-xl font-black text-slate-800 dark:text-slate-200 group-hover:text-emerald-600 transition-colors">{tenant?.firstName} {tenant?.lastName}</p>
                  </div>
                </Link>
              </div>
            </div>
          </section>
        </div>
      </div>

      {/* FIXED Multi-select Category Pop-up */}
      {isEditingCategories && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 sm:p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setIsEditingCategories(false)}>
          <div className="bg-white dark:bg-slate-900 w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200 border border-slate-200 dark:border-white/5 flex flex-col max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6 shrink-0">
              <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Edit Service Types</h3>
              <button onClick={() => setIsEditingCategories(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><i className="fa-solid fa-xmark text-lg"></i></button>
            </div>
            <p className="text-xs text-slate-500 dark:text-slate-400 mb-6 font-medium shrink-0">Tag all applicable maintenance categories for precise operational reporting.</p>
            <div className="space-y-1.5 overflow-y-auto pr-2 scrollbar-hide flex-1">
              {availableCategories.map(cat => {
                const isSelected = request.category.includes(cat);
                return (
                  <button 
                    key={cat} 
                    onClick={() => toggleCategory(cat)}
                    className={`w-full flex items-center justify-between px-5 py-3.5 text-xs font-black uppercase rounded-2xl transition-all ${isSelected ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-500 dark:text-slate-400'}`}
                  >
                    <span>{cat}</span>
                    {isSelected && <i className="fa-solid fa-check"></i>}
                  </button>
                );
              })}
            </div>
            <button onClick={() => setIsEditingCategories(false)} className="w-full mt-8 py-4 bg-slate-900 dark:bg-emerald-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all shrink-0">Save & Finalize</button>
          </div>
        </div>
      )}
    </div>
  );
