import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { MOCK_REQUESTS, MOCK_UNITS, MOCK_TENANTS } from '../constants';
import { RequestStatus, MaintenanceNote, MaintenanceExpense, MaintenanceCategory, MaintenanceRequest } from '../types';

const MaintenanceDetail: React.FC<{ isAdmin?: boolean }> = ({ isAdmin = false }) => {
  const { requestId } = useParams<{ requestId: string }>();
  const navigate = useNavigate();
  const userUnitId = 'u1';
  const [request, setRequest] = useState(MOCK_REQUESTS.find(r => r.id === requestId));

  // Access control check
  if (request && !isAdmin && request.unitId !== userUnitId) {
    return (
      <div className="p-12 text-center bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
        <i className="fa-solid fa-shield-halved text-5xl text-rose-500 mb-4 opacity-20"></i>
        <h2 className="text-2xl font-black text-slate-800 dark:text-white mb-2">Access Restricted</h2>
        <p className="text-slate-500 dark:text-slate-400 font-medium">You are only authorized to view service records for your assigned unit (101).</p>
        <Link to="/maintenance" className="mt-8 inline-block bg-slate-900 dark:bg-emerald-600 text-white px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all">Return to Queue</Link>
      </div>
    );
  }

  const unit = MOCK_UNITS.find(u => u.id === request?.unitId);
  const tenant = MOCK_TENANTS.find(t => t.id === request?.tenantId);

  const [newNote, setNewNote] = useState('');
  const [newItem, setNewItem] = useState('');
  const [newCost, setNewCost] = useState('');
  const [isEditingCategories, setIsEditingCategories] = useState(false);
  const [showReopenModal, setShowReopenModal] = useState(false);
  const [reopenReason, setReopenReason] = useState('');

  if (!request) return <div className="p-12 text-center text-slate-500 font-bold">Ticket not found in archive.</div>;

  const isLocked = request.status === RequestStatus.COMPLETED || request.status === RequestStatus.CANCELLED;

  const handleStatusChange = (status: RequestStatus) => {
    if (isLocked) return;
    setRequest(prev => prev ? { ...prev, status, updatedAt: new Date().toISOString() } : undefined);
  };

  const toggleCategory = (cat: MaintenanceCategory) => {
    setRequest(prev => {
      if (!prev) return undefined;
      const current = prev.category;
      const next = current.includes(cat) ? current.filter(c => c !== cat) : [...current, cat];
      return { ...prev, category: next, updatedAt: new Date().toISOString() };
    });
  };

  const addNote = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newNote.trim() || isLocked) return;
    const note: MaintenanceNote = {
      id: `n${Date.now()}`,
      author: isAdmin ? 'Board Admin' : 'Member Note',
      date: new Date().toISOString(),
      content: newNote.trim()
    };
    setRequest(prev => prev ? { ...prev, notes: [...prev.notes, note] } : undefined);
    setNewNote('');
  };

  const addExpense = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim() || !newCost || isLocked) return;
    const expense: MaintenanceExpense = {
      id: `ex${Date.now()}`,
      item: newItem.trim(),
      cost: parseFloat(newCost),
      date: new Date().toISOString().split('T')[0]
    };
    setRequest(prev => prev ? { ...prev, expenses: [...prev.expenses, expense] } : undefined);
    setNewItem('');
    setNewCost('');
  };

  const handleReopen = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reopenReason.trim()) return;
    setRequest(prev => prev ? { ...prev, status: RequestStatus.IN_PROGRESS, updatedAt: new Date().toISOString() } : undefined);
    setShowReopenModal(false);
    setReopenReason('');
  };

  const totalExpenses = request.expenses.reduce((acc, curr) => acc + curr.cost, 0);
  const availableCategories: MaintenanceCategory[] = ['Plumbing', 'Electrical', 'Structural', 'Appliance', 'HVAC', 'Exterior', 'Safety', 'Other'];

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12 animate-in fade-in duration-500">
      <div className="flex items-center justify-between gap-4 text-slate-500 text-sm mb-2">
        <Link to="/maintenance" className="hover:text-emerald-600 transition-colors flex items-center gap-1 font-bold">
          <i className="fa-solid fa-arrow-left"></i> Maintenance Queue
        </Link>
        {isLocked && (
          <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
            <i className="fa-solid fa-lock"></i> Record Finalized
          </span>
        )}
      </div>

      {/* RAG Status Bar */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
        <div className="grid grid-cols-2 sm:grid-cols-4 w-full gap-3">
          {(Object.values(RequestStatus)).map((status) => {
            const isActive = request.status === status;
            return (
              <button
                key={status}
                disabled={(isLocked || !isAdmin) && !isActive}
                onClick={() => isAdmin && handleStatusChange(status)}
                className={`py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  isActive 
                    ? `bg-emerald-600 text-white shadow-lg shadow-emerald-500/10 dark:shadow-none scale-105 z-10` 
                    : isAdmin 
                      ? 'bg-slate-50 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-60 hover:opacity-100'
                      : 'bg-slate-50 dark:bg-slate-800 text-slate-300 dark:text-slate-700 opacity-30 cursor-not-allowed'
                }`}
              >
                {status}
              </button>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm">
            <div className="flex flex-wrap gap-2 mb-6">
              {request.category.map(cat => (
                <span key={cat} className="text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-300">
                  <i className="fa-solid fa-tag mr-2"></i>{cat}
                </span>
              ))}
              {isAdmin && !isLocked && <button onClick={() => setIsEditingCategories(true)} className="text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-dashed border-slate-300 dark:border-slate-700 text-slate-400 hover:border-emerald-500 transition-colors">+ Edit Service Type</button>}
            </div>

            <h1 className="text-4xl font-black text-slate-900 dark:text-white leading-tight mb-8">{request.description}</h1>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-8 border-t border-slate-50 dark:border-white/5">
              <div className="flex items-center gap-4 group p-5 bg-slate-50 dark:bg-slate-950/30 rounded-2xl border border-transparent">
                <div className="w-14 h-14 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center text-slate-400 shadow-inner">
                  <i className="fa-solid fa-door-open text-2xl"></i>
                </div>
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Asset Location</p>
                  <p className="text-xl font-black text-slate-800 dark:text-slate-200">Unit #{unit?.number}</p>
                </div>
              </div>
              <div className="flex items-center gap-4 group p-5 bg-slate-50 dark:bg-slate-950/30 rounded-2xl border border-transparent">
                <div className="w-14 h-14 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center text-slate-400 shadow-inner">
                  <i className="fa-solid fa-user-circle text-2xl"></i>
                </div>
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Submitted By</p>
                  <p className="text-xl font-black text-slate-800 dark:text-slate-200">{tenant?.firstName} {tenant?.lastName}</p>
                </div>
              </div>
            </div>
          </section>

          {/* Activity Log Feed */}
          <section className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 dark:border-white/5 bg-slate-50/50 dark:bg-slate-950/50">
              <h3 className="font-black text-slate-800 dark:text-white uppercase tracking-widest text-xs">Activity Log & Dispatch Feed</h3>
            </div>
            <div className="p-6 space-y-6">
              {request.notes.map((note) => (
                <div key={note.id} className="flex gap-4">
                  <div className="w-8 h-8 rounded-xl bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-[10px] font-black text-slate-400 shrink-0 uppercase">
                    {note.author[0]}
                  </div>
                  <div className="flex-1 pb-4 border-b border-slate-50 dark:border-white/5">
                    <div className="flex justify-between items-start mb-1">
                      <p className="text-sm font-black text-slate-800 dark:text-white">{note.author}</p>
                      <p className="text-[10px] text-slate-400 font-bold">{new Date(note.date).toLocaleDateString()}</p>
                    </div>
                    <p className="text-sm leading-relaxed text-slate-600 dark:text-slate-400 font-medium">
                      {note.content}
                    </p>
                  </div>
                </div>
              ))}
              {!isLocked && (
                <form onSubmit={addNote} className="pt-4">
                  <textarea
                    className="w-full bg-slate-50 dark:bg-slate-950/50 border border-slate-200 dark:border-white/10 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-emerald-500 outline-none text-slate-800 dark:text-slate-200 shadow-inner"
                    placeholder={isAdmin ? "Log a new update or member contact..." : "Add a comment for the maintenance committee..."}
                    value={newNote}
                    onChange={(e) => setNewNote(e.target.value)}
                  />
                  <div className="flex justify-end mt-3">
                    <button type="submit" className="bg-slate-900 dark:bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg dark:shadow-none transition-all active:scale-95">Post Update</button>
                  </div>
                </form>
              )}
            </div>
          </section>

          {/* Cost Ledger Section - Only for Admin */}
          {isAdmin && (
            <section className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-white/5 shadow-sm overflow-hidden">
              <div className="p-6 border-b border-slate-100 dark:border-white/5 bg-slate-50/50 dark:bg-slate-950/50 flex justify-between items-center">
                <h3 className="font-black text-slate-800 dark:text-white uppercase tracking-widest text-xs">Incident Expenditure Ledger</h3>
                <p className="text-sm font-black text-emerald-600 dark:text-emerald-400">Total: ${totalExpenses.toFixed(2)}</p>
              </div>
              <div className="p-6">
                {!isLocked && (
                  <form onSubmit={addExpense} className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-6 p-4 bg-slate-50 dark:bg-slate-950/30 rounded-2xl">
                     <input type="text" placeholder="Service/Part" className="col-span-1 bg-white dark:bg-slate-800 border dark:border-white/10 rounded-xl px-4 py-2 text-xs font-bold" value={newItem} onChange={e => setNewItem(e.target.value)} />
                     <input type="number" placeholder="0.00" className="col-span-1 bg-white dark:bg-slate-800 border dark:border-white/10 rounded-xl px-4 py-2 text-xs font-bold" value={newCost} onChange={e => setNewCost(e.target.value)} />
                     <button type="submit" className="bg-emerald-600 text-white rounded-xl text-[10px] font-black uppercase shadow-emerald-500/10 dark:shadow-none">Add Item</button>
                  </form>
                )}
                <div className="overflow-x-auto">
                   <table className="w-full text-left">
                      <thead className="bg-slate-50 dark:bg-slate-950/20">
                         <tr>
                            <th className="px-4 py-2 text-[8px] font-black uppercase tracking-widest text-slate-400">Date</th>
                            <th className="px-4 py-2 text-[8px] font-black uppercase tracking-widest text-slate-400">Description</th>
                            <th className="px-4 py-2 text-[8px] font-black uppercase tracking-widest text-slate-400 text-right">Cost</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50 dark:divide-white/5">
                         {request.expenses.map(exp => (
                           <tr key={exp.id}>
                              <td className="px-4 py-3 text-[10px] font-bold text-slate-500">{exp.date}</td>
                              <td className="px-4 py-3 text-xs font-black text-slate-800 dark:text-slate-200">{exp.item}</td>
                              <td className="px-4 py-3 text-sm font-black text-slate-900 dark:text-white text-right">${exp.cost.toFixed(2)}</td>
                           </tr>
                         ))}
                         {request.expenses.length === 0 && (
                           <tr><td colSpan={3} className="px-4 py-8 text-center text-[10px] font-black uppercase text-slate-300">No costs recorded.</td></tr>
                         )}
                      </tbody>
                   </table>
                </div>
              </div>
            </section>
          )}
        </div>

        <div className="space-y-6">
          <div className="bg-slate-900 dark:bg-slate-950 text-white p-8 rounded-3xl shadow-xl">
             <h3 className="text-emerald-400 font-black uppercase text-[10px] tracking-widest mb-6">Work Order Actions</h3>
             <div className="space-y-3">
                <button onClick={() => window.print()} className="w-full p-4 bg-emerald-600 text-white rounded-2xl flex items-center justify-center gap-3 hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-500/10 dark:shadow-none active:scale-95 group">
                  <i className="fa-solid fa-print group-hover:scale-110 transition-transform"></i>
                  <span className="text-[10px] font-black uppercase tracking-widest">Print Order</span>
                </button>
                {isLocked && isAdmin && (
                  <button onClick={() => setShowReopenModal(true)} className="w-full p-4 bg-white/10 border border-white/20 rounded-2xl flex items-center justify-center gap-3 hover:bg-white/20 transition-all">
                    <i className="fa-solid fa-rotate-left text-amber-500"></i>
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">Re-open Case</span>
                  </button>
                )}
                {isAdmin && (
                  <button onClick={() => alert("Resident has been notified via Portal and Email.")} className="w-full p-4 bg-white/5 border border-white/10 rounded-2xl flex items-center justify-center gap-3 hover:bg-white/10 transition-colors">
                    <i className="fa-solid fa-envelope text-blue-400"></i>
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">Resend Alert</span>
                  </button>
                )}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MaintenanceDetail;

import React, { useState } from 'react';
import { MOCK_DOCS } from '../constants';
import { geminiService } from '../services/geminiService';

const Documents: React.FC<{ isAdmin: boolean }> = ({ isAdmin }) => {
  const [filter, setFilter] = useState('All');
  const [question, setQuestion] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [showUpload, setShowUpload] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);

  const categories = ['All', 'Minutes', 'Policy', 'Financial', 'Bylaws'];
  const filteredDocs = filter === 'All' ? MOCK_DOCS : MOCK_DOCS.filter(d => d.category === filter);

  const handleAskAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!question) return;
    setLoading(true);
    setAiResponse('');

    const context = MOCK_DOCS.filter(d => d.category === 'Policy').map(d => d.title).join(', ');

    try {
      const answer = await geminiService.askPolicyQuestion(question, context);
      setAiResponse(answer || 'Sorry, I could not find an answer.');
    } catch (err) {
      setAiResponse('Error communicating with AI Assistant.');
    } finally {
      setLoading(false);
    }
  };

  const handleSimulatedUpload = () => {
    setIsUploading(true);
    let prog = 0;
    const interval = setInterval(() => {
      prog += 10;
      setUploadProgress(prog);
      if (prog >= 100) {
        clearInterval(interval);
        setTimeout(() => {
          setIsUploading(false);
          setUploadProgress(0);
          setShowUpload(false);
          alert("Document uploaded and archived in association library.");
        }, 500);
      }
    }, 150);
  };

  return (
    <div className="space-y-6 lg:space-y-8 max-w-7xl mx-auto pb-12">
      <div className="bg-slate-900 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 p-8 opacity-5 text-[15rem] pointer-events-none group-hover:opacity-10 transition-opacity">
          <i className="fa-solid fa-wand-magic-sparkles"></i>
        </div>
        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-6">
            <div className="w-12 h-12 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-500/10 dark:shadow-none">
              <i className="fa-solid fa-robot text-xl"></i>
            </div>
            <div>
              <h3 className="text-xl font-black uppercase tracking-tight">Co-op AI Policy Guard</h3>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Instant association rule lookup</p>
            </div>
          </div>
          <form onSubmit={handleAskAI} className="relative">
            <input
              type="text"
              className="w-full bg-slate-800 border border-slate-700 rounded-2xl px-6 py-4 pr-32 outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm font-medium shadow-inner"
              placeholder="e.g., How many days notice for a general meeting?"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
            />
            <button 
              type="submit"
              disabled={loading}
              className="absolute right-2 top-2 bottom-2 bg-emerald-600 hover:bg-emerald-700 text-white px-6 rounded-xl text-[10px] font-black uppercase transition-all flex items-center gap-2 active:scale-95 shadow-lg shadow-emerald-500/10 dark:shadow-none"
            >
              {loading ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-bolt"></i>}
              Query
            </button>
          </form>
          {aiResponse && (
            <div className="mt-6 p-6 bg-white/5 border border-white/10 rounded-2xl text-sm leading-relaxed animate-in fade-in slide-in-from-top-2">
              <div className="flex items-center gap-2 mb-3">
                <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest border border-emerald-500/30 px-2 py-0.5 rounded">AI Result</span>
              </div>
              <p className="text-slate-200 font-medium leading-relaxed">{aiResponse}</p>
            </div>
          )}
        </div>
      </div>

      <div className="flex flex-col gap-6">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <h3 className="text-2xl font-black text-slate-800 dark:text-white">Resource Library</h3>
          {isAdmin && (
            <button 
              onClick={() => setShowUpload(!showUpload)}
              className="w-full sm:w-auto bg-emerald-600 text-white px-6 py-3 rounded-xl font-black text-xs uppercase flex items-center justify-center gap-2 shadow-lg shadow-emerald-500/10 dark:shadow-none active:scale-95 transition-all"
            >
              <i className="fa-solid fa-cloud-arrow-up"></i>
              Archive Document
            </button>
          )}
        </div>

        {showUpload && (
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-white/5 shadow-xl animate-in slide-in-from-top-4">
            <div className="flex justify-between items-center mb-6">
              <h4 className="font-black text-slate-800 dark:text-white uppercase tracking-widest text-xs">Association Upload Portal</h4>
              <button onClick={() => setShowUpload(false)} className="text-slate-400 hover:text-slate-600"><i className="fa-solid fa-xmark"></i></button>
            </div>

            {isUploading ? (
              <div className="space-y-4 py-8">
                <div className="flex justify-between text-xs font-bold text-slate-500 uppercase">
                  <span>Encrypting & Archiving...</span>
                  <span>{uploadProgress}%</span>
                </div>
                <div className="w-full h-3 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                  <div className="h-full bg-emerald-500 transition-all duration-200" style={{ width: `${uploadProgress}%` }}></div>
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-slate-50 dark:bg-slate-950/50 border-2 border-dashed border-slate-200 dark:border-white/10 rounded-3xl p-10 flex flex-col items-center justify-center text-center group hover:border-emerald-400 transition-colors">
                  <i className="fa-solid fa-file-pdf text-4xl text-slate-300 group-hover:text-emerald-500 mb-4 transition-colors"></i>
                  <p className="text-xs font-black text-slate-400 uppercase">Drop associations files here</p>
                </div>
                <div className="space-y-4">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Archive Category</label>
                    <select className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-white/10 rounded-xl px-4 py-3 text-sm font-bold text-slate-800 dark:text-slate-200">
                      {categories.filter(c => c !== 'All').map(c => <option key={c}>{c}</option>)}
                    </select>
                  </div>
                  <div className="bg-amber-50 dark:bg-amber-900/10 p-4 rounded-xl border border-amber-100 dark:border-amber-900/30">
                    <p className="text-[10px] text-amber-800 dark:text-amber-500 font-bold leading-relaxed">
                      <i className="fa-solid fa-shield-halved mr-1"></i> 
                      By uploading, you certify this document complies with BC PIPA standards and does not expose unauthorized personal information.
                    </p>
                  </div>
                  <button 
                    onClick={handleSimulatedUpload}
                    className="w-full bg-slate-900 dark:bg-emerald-600 text-white py-4 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-black dark:hover:bg-emerald-700 transition-all shadow-lg active:scale-95"
                  >
                    Confirm & Upload
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        <div className="flex overflow-x-auto gap-2 scrollbar-hide">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`whitespace-nowrap px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border ${
                filter === cat 
                  ? 'bg-slate-900 dark:bg-emerald-600 text-white border-slate-900 dark:border-emerald-600 shadow-xl' 
                  : 'bg-white dark:bg-slate-800 text-slate-500 border-slate-200 dark:border-white/5 hover:border-emerald-300 hover:text-emerald-600'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredDocs.map(doc => (
            <div key={doc.id} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-white/5 hover:shadow-2xl hover:border-emerald-300 dark:hover:border-emerald-600 transition-all group flex flex-col">
              <div className="flex items-start gap-4 mb-6">
                <div className="w-14 h-14 bg-slate-100 dark:bg-slate-800 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-emerald-600 transition-all shrink-0 shadow-inner">
                  <i className="fa-solid fa-file-pdf text-2xl"></i>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h4 className="text-sm font-black text-slate-800 dark:text-white group-hover:text-emerald-700 dark:group-hover:text-emerald-400 transition-colors truncate">{doc.title}</h4>
                  <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mt-1">{doc.date} • {doc.author}</p>
                </div>
                {doc.isPrivate && <div className="p-2 bg-amber-50 dark:bg-amber-900/30 rounded-lg text-amber-500 dark:text-amber-400"><i className="fa-solid fa-lock text-[10px]"></i></div>}
              </div>
              <div className="mt-auto flex items-center justify-between pt-4 border-t border-slate-50 dark:border-white/5">
                <span className="text-[9px] font-black px-2 py-1 rounded bg-slate-50 dark:bg-slate-800 text-slate-500 dark:text-slate-400 uppercase tracking-widest border border-slate-100 dark:border-white/5">{doc.category}</span>
                <button className="w-10 h-10 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-white rounded-xl flex items-center justify-center hover:bg-emerald-600 transition-all active:scale-95">
                  <i className="fa-solid fa-download"></i>
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Documents;
